import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';
import { ConfirmModal } from './ConfirmModal';
import { getFlexibleCandidate, canPlay, TBD_PLAYER } from '../utils/matchmaker';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  onMinimize: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
  onUpdatePlayer: (updatedPlayer: Player) => void;
}

interface InternalMatch {
    id: number;
    label: string;
    mode: string;
    teamA: any;
    teamB: any;
}

type BracketPhase = 'TEAM_REVEAL' | 'OVERVIEW' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

const ScrambleText: React.FC<{ text: string; isRevealed: boolean }> = ({ text, isRevealed }) => {
  const [display, setDisplay] = useState(isRevealed ? text : 'INITIALIZING...');

  useEffect(() => {
    if (!isRevealed) {
        const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789#@&";
        const interval = setInterval(() => {
            setDisplay(Array(text.length).fill(0).map(() => chars[Math.floor(Math.random() * chars.length)]).join(''));
        }, 50);
        return () => clearInterval(interval);
    } else {
        let iteration = 0;
        const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
        const interval = setInterval(() => {
            setDisplay(text.split("").map((letter, index) => {
                if (index < iteration) return letter;
                return chars[Math.floor(Math.random() * chars.length)];
            }).join(""));
            if (iteration >= text.length) clearInterval(interval);
            iteration += 1/2; 
        }, 30);
        return () => clearInterval(interval);
    }
  }, [text, isRevealed]);

  return <span>{display}</span>;
};

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, onMinimize, activePlayers, onReroll, onUpdatePlayer }) => {
  const [phase, setPhase] = useState<BracketPhase>('TEAM_REVEAL');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // Team Reveal State
  const [revealedTeamIndices, setRevealedTeamIndices] = useState<Set<number>>(new Set());
  const [isGlobalRolling, setIsGlobalRolling] = useState(false);
  const [isGlobalRevealComplete, setIsGlobalRevealComplete] = useState(false);

  const [globalAssignments, setGlobalAssignments] = useState<Record<string, string>>(() => {
      const initial: Record<string, string> = {};
      match.teams.forEach((team, tIdx) => {
          team.slots.forEach(slot => {
              if (slot.player && slot.player.id !== 'tbd') {
                  initial[`${tIdx}-${slot.role}`] = slot.player.id;
              }
          });
      });
      return initial;
  });

  useEffect(() => {
      setGlobalAssignments(prev => {
          const next = { ...prev };
          match.teams.forEach((team, tIdx) => {
              team.slots.forEach(slot => {
                  if (slot.player && slot.player.id !== 'tbd') {
                      next[`${tIdx}-${slot.role}`] = slot.player.id;
                  }
              });
          });
          return next;
      });
  }, [match]);

  const [showAbortConfirm, setShowAbortConfirm] = useState(false);
  const [renameState, setRenameState] = useState<{ isOpen: boolean; player: Player | null; newName: string }>({
    isOpen: false,
    player: null,
    newName: ''
  });

  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  const getAssignedPlayer = useCallback((teamIdx: number, role: Role): Player => {
      const key = `${teamIdx}-${role}`;
      const pid = globalAssignments[key];
      if (pid) {
          return activePlayers.find(p => p.id === pid) || TBD_PLAYER;
      }
      return TBD_PLAYER;
  }, [globalAssignments, activePlayers]);

  const { roundOneMatches, quarterMatches, semiMatches, grandFinalMatch, allMatches, hasRoundOne } = useMemo(() => {
      const getTeamObj = (teamIndex: number) => {
          if (teamIndex < 0 || teamIndex >= match.teams.length) return null;
          const original = match.teams[teamIndex];
          const updatedSlots = original.slots.map(s => ({
              ...s,
              player: getAssignedPlayer(teamIndex, s.role)
          }));
          return { ...original, slots: updatedSlots };
      };

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const numTeams = match.teams.length;

      // Logika khusus 12 Tim
      if (numTeams === 12) {
          const r1: InternalMatch[] = [];
          for (let i = 0; i < 4; i++) {
              r1.push({ id: i, label: `PLAY-IN ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
          const qm: InternalMatch[] = [];
          qm.push({ id: 4, label: 'QUARTER 1', mode: 'BO1', teamA: getWinnerTeam(0, r1[0].teamA, r1[0].teamB), teamB: getTeamObj(8) });
          qm.push({ id: 5, label: 'QUARTER 2', mode: 'BO1', teamA: getWinnerTeam(1, r1[1].teamA, r1[1].teamB), teamB: getTeamObj(9) });
          qm.push({ id: 6, label: 'QUARTER 3', mode: 'BO1', teamA: getWinnerTeam(2, r1[2].teamA, r1[2].teamB), teamB: getTeamObj(10) });
          qm.push({ id: 7, label: 'QUARTER 4', mode: 'BO1', teamA: getWinnerTeam(3, r1[3].teamA, r1[3].teamB), teamB: getTeamObj(11) });

          const sm: InternalMatch[] = [];
          sm.push({ id: 8, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(4, qm[0].teamA, qm[0].teamB), teamB: getWinnerTeam(5, qm[1].teamA, qm[1].teamB) });
          sm.push({ id: 9, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(6, qm[2].teamA, qm[2].teamB), teamB: getWinnerTeam(7, qm[3].teamA, qm[3].teamB) });

          const gf: InternalMatch = { id: 10, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(8, sm[0].teamA, sm[0].teamB), teamB: getWinnerTeam(9, sm[1].teamA, sm[1].teamB) };

          return { roundOneMatches: r1, quarterMatches: qm, semiMatches: sm, grandFinalMatch: gf, allMatches: [...r1, ...qm, ...sm, gf], hasRoundOne: true };
      }

      // Existing logics for 3, 4, 5, 6, 8 teams...
      if (numTeams === 3) {
        const m0: InternalMatch = { id: 0, label: 'ELIMINATION', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const m1: InternalMatch = { id: 1, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(0, m0.teamA, m0.teamB), teamB: getTeamObj(2) };
        const m2: InternalMatch = { id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, m0.teamA, m0.teamB), teamB: getWinnerTeam(1, m1.teamA, m1.teamB) };
        const matches: InternalMatch[] = [m0, m1, m2];
        return { roundOneMatches: [], quarterMatches: [], semiMatches: [m0, m1], grandFinalMatch: m2, allMatches: matches, hasRoundOne: false };
      }

      if (numTeams === 5 || numTeams === 6) {
        const q0: InternalMatch = { id: 0, label: 'QUARTER 1', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const q1: InternalMatch = { id: 1, label: 'QUARTER 2', mode: 'BO1', teamA: getTeamObj(2), teamB: getTeamObj(3) };
        const q2: InternalMatch = { id: 2, label: 'QUARTER 3', mode: 'BO1', teamA: getTeamObj(4), teamB: getTeamObj(5) || null };
        const s1: InternalMatch = { id: 3, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, q0.teamA, q0.teamB), teamB: getWinnerTeam(1, q1.teamA, q1.teamB) };
        const s2: InternalMatch = { id: 4, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, q2.teamA, q2.teamB), teamB: getLoserTeam(3, s1.teamA, s1.teamB) };
        const gf: InternalMatch = { id: 5, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(3, s1.teamA, s1.teamB), teamB: getWinnerTeam(4, s2.teamA, s2.teamB) };
        return { roundOneMatches: [], quarterMatches: [q0, q1, q2], semiMatches: [s1, s2], grandFinalMatch: gf, allMatches: [q0, q1, q2, s1, s2, gf], hasRoundOne: false };
      }

      const qMatches: InternalMatch[] = [];
      if (numTeams === 8) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }
      const sMatches: InternalMatch[] = [];
      if (numTeams === 8) {
          sMatches.push({ id: 4, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, qMatches[0].teamA, qMatches[0].teamB), teamB: getWinnerTeam(1, qMatches[1].teamA, qMatches[1].teamB) });
          sMatches.push({ id: 5, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, qMatches[2].teamA, qMatches[2].teamB), teamB: getWinnerTeam(3, qMatches[3].teamA, qMatches[3].teamB) });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({ id: i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }
      const gfIndex = numTeams === 8 ? 6 : 2;
      const gf: InternalMatch = { id: gfIndex, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB), teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB) };
      return { roundOneMatches: [], quarterMatches: qMatches, semiMatches: sMatches, grandFinalMatch: gf, allMatches: [...qMatches, ...sMatches, gf], hasRoundOne: false };
  }, [match, scores, globalAssignments, getAssignedPlayer]); 

  const activeMatchData = useMemo(() => {
    const data = allMatches.find(m => m.id === currentMatchIdx);
    if (!data) return undefined;
    if (data.label === 'GRAND FINAL') {
        const sA = scores[`${currentMatchIdx}-A`] || 0;
        const sB = scores[`${currentMatchIdx}-B`] || 0;
        if ((sA + sB) % 2 !== 0) return { ...data, teamA: data.teamB, teamB: data.teamA };
    }
    return data;
  }, [allMatches, currentMatchIdx, scores]);

  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);
    setPhase('TRANSITION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let isSwapped = false;
     if (currentMatchIdx === grandFinalMatch.id) {
         const gamesPlayed = currentScoreA + currentScoreB;
         if (gamesPlayed % 2 !== 0) isSwapped = true;
     }
     let incrementA = 0; let incrementB = 0;
     if (currentRoundWinner === 'azure') { if (isSwapped) incrementB = 1; else incrementA = 1; } 
     else if (currentRoundWinner === 'crimson') { if (isSwapped) incrementA = 1; else incrementB = 1; }
     let newScoreA = currentScoreA + incrementA;
     let newScoreB = currentScoreB + incrementB;
     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));
     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const submitRename = () => {
    if (renameState.player && renameState.newName.trim()) {
        onUpdatePlayer({ ...renameState.player, name: renameState.newName.trim() });
        setRenameState({ isOpen: false, player: null, newName: '' });
    }
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reroll' && wheelState.winnerPlayer && activeMatchData) {
        const side = wheelState.team;
        const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
        const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
        if (teamIdx !== -1) {
            setGlobalAssignments(prev => ({ ...prev, [`${teamIdx}-${wheelState.role}`]: wheelState.winnerPlayer!.id }));
            onReroll(teamIdx, wheelState.role, wheelState.winnerPlayer!);
        }
    }
    setWheelState(null);
  };

  const handleStartGlobalReveal = () => {
     setIsGlobalRolling(true);
     match.teams.forEach((_, idx) => {
         setTimeout(() => {
             setRevealedTeamIndices(prev => new Set(prev).add(idx));
             if (idx === match.teams.length - 1) {
                 setTimeout(() => {
                     setIsGlobalRolling(false);
                     setIsGlobalRevealComplete(true);
                 }, 1500);
             }
         }, (idx + 1) * 2000); // Stagger reveal
     });
  };

  const renderPlayerCard = (role: Role, side: 'azure' | 'crimson') => {
    if (!activeMatchData) return null;
    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
    const player = teamData ? teamData.slots.find(s => s.role === role)?.player : null;
    const isCoach = role === Role.COACH;

    let theme = isCoach ? { bg: 'bg-[#1a1a1a]', border: 'border-white', glow: 'shadow-[0_0_20px_rgba(255,255,255,0.6)]', text: 'text-white', gradient: 'from-white/20 to-transparent' }
      : side === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' }
      : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#c02d2d]/20 to-transparent' };

    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group`}>
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${side === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${side === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {player?.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>

           <div className={`absolute top-2 z-50 flex gap-2 transition-all opacity-0 group-hover:opacity-100 ${side === 'azure' ? 'right-4' : 'left-4'}`}>
              <button onClick={(e) => { 
                  e.stopPropagation(); 
                  if (teamIdx !== -1) {
                      const usedIds = new Set(Object.values(globalAssignments));
                      const candidates = activePlayers.filter(p => !usedIds.has(p.id) && canPlay(p, role));
                      if (candidates.length > 0) {
                          const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
                          setWheelState({ isOpen: true, type: 'reroll', team: side, role, winnerName: newPlayer.name, winnerPlayer: newPlayer, candidates: candidates.map(p => p.name), duration: 4000 });
                      }
                  }
              }} className="p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full text-white hover:text-black transition-all" title="Reroll Player"><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
              <button onClick={(e) => { e.stopPropagation(); if(player) setRenameState({ isOpen: true, player, newName: player.name }); }} className="p-2.5 bg-black/60 hover:bg-[#00d2ff] rounded-full text-white hover:text-black transition-all" title="Change Nickname"><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
           </div>
        </div>
      </div>
    );
  };

  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" style={{ height: `${height}px`, ...style }}>
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b"><animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" /></stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%"><feGaussianBlur stdDeviation="3" result="blur"/><feComposite in="SourceGraphic" in2="blur" operator="over"/></filter>
          </defs>
          {type === 'fork' ? (
             <path d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} stroke="url(#energyLine)" strokeWidth="2.5" fill="none" filter="url(#energyGlow)" strokeLinecap="round" />
          ) : (
             <path d={`M 0,${height/2} L 100,${height/2}`} stroke="url(#energyLine)" strokeWidth="2.5" fill="none" filter="url(#energyGlow)" strokeLinecap="round" />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)"><animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} dur="2s" repeatCount="indefinite" /></circle>
          {type === 'fork' && (<circle r="3" fill="#fff" filter="url(#energyGlow)"><animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" /></circle>)}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: InternalMatch) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;
      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-md p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>
            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>
                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1"><div className="h-[1px] flex-1 bg-white"></div><span className="text-[8px] font-black italic text-[#8a9db8]">VS</span><div className="h-[1px] flex-1 bg-white"></div></div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>
            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-center">
                        <span className="text-[8px] text-[#dcb06b]/50 font-black uppercase tracking-widest">AUTO ADVANCE</span>
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => { const val = e.target.value.replace(/\D/g,'').slice(0,4); setMatchRoomIds(prev => ({ ...prev, [m.id]: val })); }} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----" />
                        </div>
                        {!isDone && m.teamA && m.teamB && <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">START</Button>}
                    </>
                )}
            </div>
        </div>
      );
  };

  const renderTeamRevealScreen = () => {
     return (
        <div className="min-h-screen bg-[#05090f] p-8 md:p-12 relative overflow-hidden flex flex-col items-center">
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,#1e3a5f_0%,#05090f_70%)] opacity-30 pointer-events-none"></div>

            <div className="relative z-10 text-center mb-12 animate-slide-in">
                <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] uppercase drop-shadow-[0_0_20px_rgba(220,176,107,0.5)]">TEAM DRAFTING</h1>
                <div className="h-1 w-32 bg-[#dcb06b] mx-auto mt-4 mb-2"></div>
                <p className="text-[#8a9db8] font-orbitron tracking-widest text-xs">OFFICIAL ROSTER ASSIGNMENT PROTOCOL</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 w-full max-w-7xl mb-24">
                {match.teams.map((team, idx) => {
                    const isRevealed = revealedTeamIndices.has(idx);

                    return (
                        <div key={idx} className={`relative bg-[#0a1a2f]/80 border ${isRevealed ? 'border-[#dcb06b] shadow-[0_0_20px_rgba(220,176,107,0.2)]' : 'border-[#1e3a5f]'} clip-corner-md transition-all duration-700 p-1`}>
                            <div className="bg-[#05090f] p-4 h-full flex flex-col clip-corner-sm">
                                <div className="flex items-center justify-between mb-4 pb-2 border-b border-white/10">
                                    <div className="flex items-center gap-2">
                                        <div className="w-3 h-3 rounded-full" style={{ backgroundColor: team.color }}></div>
                                        <h3 className="font-orbitron font-bold text-white tracking-widest text-sm truncate max-w-[150px]">{team.name}</h3>
                                    </div>
                                    <span className="text-[9px] text-[#4a5f78] font-black uppercase">{isRevealed ? 'LOCKED' : 'PENDING'}</span>
                                </div>
                                <div className="space-y-2 flex-1">
                                    {ROLES_ORDER.map(role => {
                                        const slot = team.slots.find(s => s.role === role);
                                        const player = getAssignedPlayer(idx, role);

                                        return (
                                            <div key={role} className="flex items-center gap-3 p-2 bg-black/20 rounded border border-white/5">
                                                <div className={`text-[#8a9db8] scale-75 w-6 flex justify-center`}>{RoleIcons[role]}</div>
                                                <div className={`text-xs font-orbitron font-bold truncate ${isRevealed ? 'text-white' : 'text-[#4a5f78]'}`}>
                                                    <ScrambleText text={player?.name || '???'} isRevealed={isRevealed} />
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>

            <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-[#05090f] via-[#05090f]/90 to-transparent flex justify-center z-50">
                {!isGlobalRevealComplete ? (
                    <Button 
                        onClick={handleStartGlobalReveal} 
                        disabled={isGlobalRolling} 
                        className={`px-16 py-4 text-xl tracking-[0.2em] shadow-[0_0_30px_rgba(220,176,107,0.3)] ${isGlobalRolling ? 'opacity-50 cursor-not-allowed' : 'animate-pulse'}`}
                    >
                        {isGlobalRolling ? 'INITIALIZING DRAFT...' : 'COMMENCE ROLL'}
                    </Button>
                ) : (
                    <Button 
                        onClick={() => setPhase('OVERVIEW')} 
                        className="px-16 py-4 text-xl tracking-[0.2em] shadow-[0_0_30px_rgba(220,176,107,0.3)] bg-[#0a1a2f] border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black"
                    >
                        ENTER BRACKET
                    </Button>
                )}
            </div>

            {/* Skip Button for resuming */}
            {!isGlobalRolling && !isGlobalRevealComplete && (
                <div className="absolute top-8 right-8">
                     <button onClick={() => setPhase('OVERVIEW')} className="text-[#4a5f78] hover:text-white text-[10px] font-orbitron font-bold uppercase tracking-widest border border-[#1e3a5f] px-4 py-2 hover:border-white transition-all">Skip Reveal &gt;&gt;</button>
                </div>
            )}
        </div>
     );
  };

  if (phase === 'TOURNAMENT_END') return (
      <div className="fixed inset-0 z-[300] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
        <div className="god-rays opacity-40"></div>
        <div className="relative z-20 flex flex-col items-center animate-trophy-pop w-full max-w-4xl">
            <h1 className="text-5xl md:text-8xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] mb-12 tracking-[0.2em] text-center px-4">TOURNAMENT CHAMPIONS</h1>
            <h2 className="text-6xl md:text-9xl font-black font-cinzel text-white text-center drop-shadow-[0_0_20px_#dcb06b] mb-12" style={{ color: tournamentChampion?.color }}>{tournamentChampion?.name}</h2>
            <Button onClick={onReset} size="lg" className="px-24 h-20 text-xl shadow-[0_0_50px_rgba(220,176,107,0.5)]">RETURN TO LOBBY</Button>
        </div>
      </div>
  );

  const overlayBackButton = (
      <div className="fixed top-6 left-6 z-[300]">
            <Button variant="outline" size="sm" onClick={onMinimize} className="bg-black/80 border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black">LOBBY</Button>
      </div>
  );

  if (phase === 'TEAM_REVEAL') return renderTeamRevealScreen();
  if (phase === 'TRANSITION' && activeMatchData) return <>{overlayBackButton}<PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} azureTeamName={activeMatchData.teamA?.name || 'TBD'} crimsonTeamName={activeMatchData.teamB?.name || 'TBD'} onComplete={() => setPhase('DECLARE_WIN')} /></>;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <>{overlayBackButton}<MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now(), azureTeamName: activeMatchData.teamA?.name, crimsonTeamName: activeMatchData.teamB?.name }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} /></>;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} azureTeamName={activeMatchData.teamA?.name} crimsonTeamName={activeMatchData.teamB?.name} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <>{overlayBackButton}<EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now(), azureTeamName: activeMatchData.teamA?.name, crimsonTeamName: activeMatchData.teamB?.name }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} /></>;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {/* Rename Modal UI */}
      {renameState.isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })}></div>
          <div className="relative w-full max-w-sm bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_30px_rgba(220,176,107,0.3)] animate-slide-in p-6">
            <h3 className="text-[#dcb06b] font-cinzel font-bold text-lg mb-4 text-center tracking-widest">CHANGE NICKNAME</h3>
            <input type="text" value={renameState.newName} onChange={e => setRenameState({ ...renameState, newName: e.target.value })} className="w-full bg-black/50 border border-[#1e3a5f] p-3 text-white font-orbitron focus:border-[#dcb06b] outline-none mb-6 text-center" autoFocus />
            <div className="flex gap-3">
              <Button variant="secondary" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })} className="flex-1">CANCEL</Button>
              <Button onClick={submitRename} className="flex-1">CONFIRM</Button>
            </div>
          </div>
        </div>
      )}

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="absolute top-8 left-8"><Button variant="outline" size="sm" onClick={onMinimize}>LOBBY</Button></div>
          <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-16 uppercase">TOURNAMENT BRACKET</h1>
          <div className="flex gap-16 md:gap-24 items-center justify-center relative py-20">
            {hasRoundOne && (<div className="flex flex-col gap-8 relative">{roundOneMatches.map((m, i) => (<div key={m.id} className="relative">{renderBracketMatchCard(m)}{i % 2 === 0 && <EnergyConnector type="fork" height={218} style={{top:'50%'}}/>}</div>))}</div>)}
            <div className="flex flex-col gap-32 relative">{quarterMatches.map((m, i) => (<div key={m.id} className="relative">{renderBracketMatchCard(m)}{i % 2 === 0 && <EnergyConnector type="fork" height={338} style={{top:'50%'}}/>}</div>))}</div>
            <div className="flex flex-col gap-64 relative">{semiMatches.map((m, i) => (<div key={m.id} className="relative">{renderBracketMatchCard(m)}{i === 0 && <EnergyConnector type="fork" height={458} style={{top:'50%'}}/>}</div>))}</div>
            <div className="relative scale-125 ml-10">{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={() => setShowAbortConfirm(true)} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState?.isOpen && <SpinWheel {...wheelState} roomId={activeRoomId} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')}>BACK TO BRACKET</Button>
                <div className="text-white font-orbitron font-black text-2xl tracking-[0.4em]">{activeRoomId}</div>
            </div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-32 items-end mb-6">
                    <div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-cyan-400">{activeMatchData?.teamA?.name}</h2></div>
                    <div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-red-500">{activeMatchData?.teamB?.name}</h2></div>
                </div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-32"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-10 left-0 right-0 flex justify-center">
                 <Button onClick={() => setPhase('TRANSITION')} size="lg">INITIALIZE BATTLE</Button>
            </div>
        </div>
      )}
      <ConfirmModal isOpen={showAbortConfirm} title="ABORT TOURNAMENT" message="End tournament?" onConfirm={onReset} onCancel={() => setShowAbortConfirm(false)} isDestructive />
    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';
import { ConfirmModal } from './ConfirmModal';
import { getFlexibleCandidate, canPlay, TBD_PLAYER } from '../utils/matchmaker';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  onMinimize: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
  onUpdatePlayer: (updatedPlayer: Player) => void;
}

interface InternalMatch {
    id: number;
    label: string;
    mode: string;
    teamA: any;
    teamB: any;
}

type BracketPhase = 'TEAM_REVEAL' | 'OVERVIEW' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

const ScrambleText: React.FC<{ text: string; isRevealed: boolean }> = ({ text, isRevealed }) => {
  const [display, setDisplay] = useState(isRevealed ? text : 'INITIALIZING...');

  useEffect(() => {
    if (!isRevealed) {
        const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789#@&";
        const interval = setInterval(() => {
            setDisplay(Array(text.length).fill(0).map(() => chars[Math.floor(Math.random() * chars.length)]).join(''));
        }, 50);
        return () => clearInterval(interval);
    } else {
        let iteration = 0;
        const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
        const interval = setInterval(() => {
            setDisplay(text.split("").map((letter, index) => {
                if (index < iteration) return letter;
                return chars[Math.floor(Math.random() * chars.length)];
            }).join(""));
            if (iteration >= text.length) clearInterval(interval);
            iteration += 1/2; 
        }, 30);
        return () => clearInterval(interval);
    }
  }, [text, isRevealed]);

  return <span>{display}</span>;
};

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, onMinimize, activePlayers, onReroll, onUpdatePlayer }) => {
  const [phase, setPhase] = useState<BracketPhase>('TEAM_REVEAL');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // Team Reveal State
  const [revealedTeamIndices, setRevealedTeamIndices] = useState<Set<number>>(new Set());
  const [isGlobalRolling, setIsGlobalRolling] = useState(false);
  const [isGlobalRevealComplete, setIsGlobalRevealComplete] = useState(false);

  const [globalAssignments, setGlobalAssignments] = useState<Record<string, string>>(() => {
      const initial: Record<string, string> = {};
      match.teams.forEach((team, tIdx) => {
          team.slots.forEach(slot => {
              if (slot.player && slot.player.id !== 'tbd') {
                  initial[`${tIdx}-${slot.role}`] = slot.player.id;
              }
          });
      });
      return initial;
  });

  useEffect(() => {
      setGlobalAssignments(prev => {
          const next = { ...prev };
          match.teams.forEach((team, tIdx) => {
              team.slots.forEach(slot => {
                  if (slot.player && slot.player.id !== 'tbd') {
                      next[`${tIdx}-${slot.role}`] = slot.player.id;
                  }
              });
          });
          return next;
      });
  }, [match]);

  const [showAbortConfirm, setShowAbortConfirm] = useState(false);
  const [renameState, setRenameState] = useState<{ isOpen: boolean; player: Player | null; newName: string }>({
    isOpen: false,
    player: null,
    newName: ''
  });

  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  const getAssignedPlayer = useCallback((teamIdx: number, role: Role): Player => {
      const key = `${teamIdx}-${role}`;
      const pid = globalAssignments[key];
      if (pid) {
          return activePlayers.find(p => p.id === pid) || TBD_PLAYER;
      }
      return TBD_PLAYER;
  }, [globalAssignments, activePlayers]);

  const { roundOneMatches, quarterMatches, semiMatches, grandFinalMatch, allMatches, hasRoundOne } = useMemo(() => {
      const getTeamObj = (teamIndex: number) => {
          if (teamIndex < 0 || teamIndex >= match.teams.length) return null;
          const original = match.teams[teamIndex];
          const updatedSlots = original.slots.map(s => ({
              ...s,
              player: getAssignedPlayer(teamIndex, s.role)
          }));
          return { ...original, slots: updatedSlots };
      };

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const numTeams = match.teams.length;

      // Logika khusus 12 Tim
      if (numTeams === 12) {
          const r1: InternalMatch[] = [];
          for (let i = 0; i < 4; i++) {
              r1.push({ id: i, label: `PLAY-IN ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
          const qm: InternalMatch[] = [];
          qm.push({ id: 4, label: 'QUARTER 1', mode: 'BO1', teamA: getWinnerTeam(0, r1[0].teamA, r1[0].teamB), teamB: getTeamObj(8) });
          qm.push({ id: 5, label: 'QUARTER 2', mode: 'BO1', teamA: getWinnerTeam(1, r1[1].teamA, r1[1].teamB), teamB: getTeamObj(9) });
          qm.push({ id: 6, label: 'QUARTER 3', mode: 'BO1', teamA: getWinnerTeam(2, r1[2].teamA, r1[2].teamB), teamB: getTeamObj(10) });
          qm.push({ id: 7, label: 'QUARTER 4', mode: 'BO1', teamA: getWinnerTeam(3, r1[3].teamA, r1[3].teamB), teamB: getTeamObj(11) });

          const sm: InternalMatch[] = [];
          sm.push({ id: 8, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(4, qm[0].teamA, qm[0].teamB), teamB: getWinnerTeam(5, qm[1].teamA, qm[1].teamB) });
          sm.push({ id: 9, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(6, qm[2].teamA, qm[2].teamB), teamB: getWinnerTeam(7, qm[3].teamA, qm[3].teamB) });

          const gf: InternalMatch = { id: 10, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(8, sm[0].teamA, sm[0].teamB), teamB: getWinnerTeam(9, sm[1].teamA, sm[1].teamB) };

          return { roundOneMatches: r1, quarterMatches: qm, semiMatches: sm, grandFinalMatch: gf, allMatches: [...r1, ...qm, ...sm, gf], hasRoundOne: true };
      }

      // Existing logics for 3, 4, 5, 6, 8 teams...
      if (numTeams === 3) {
        const m0: InternalMatch = { id: 0, label: 'ELIMINATION', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const m1: InternalMatch = { id: 1, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(0, m0.teamA, m0.teamB), teamB: getTeamObj(2) };
        const m2: InternalMatch = { id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, m0.teamA, m0.teamB), teamB: getWinnerTeam(1, m1.teamA, m1.teamB) };
        const matches: InternalMatch[] = [m0, m1, m2];
        return { roundOneMatches: [], quarterMatches: [], semiMatches: [m0, m1], grandFinalMatch: m2, allMatches: matches, hasRoundOne: false };
      }

      if (numTeams === 5 || numTeams === 6) {
        const q0: InternalMatch = { id: 0, label: 'QUARTER 1', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const q1: InternalMatch = { id: 1, label: 'QUARTER 2', mode: 'BO1', teamA: getTeamObj(2), teamB: getTeamObj(3) };
        const q2: InternalMatch = { id: 2, label: 'QUARTER 3', mode: 'BO1', teamA: getTeamObj(4), teamB: getTeamObj(5) || null };
        const s1: InternalMatch = { id: 3, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, q0.teamA, q0.teamB), teamB: getWinnerTeam(1, q1.teamA, q1.teamB) };
        const s2: InternalMatch = { id: 4, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, q2.teamA, q2.teamB), teamB: getLoserTeam(3, s1.teamA, s1.teamB) };
        const gf: InternalMatch = { id: 5, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(3, s1.teamA, s1.teamB), teamB: getWinnerTeam(4, s2.teamA, s2.teamB) };
        return { roundOneMatches: [], quarterMatches: [q0, q1, q2], semiMatches: [s1, s2], grandFinalMatch: gf, allMatches: [q0, q1, q2, s1, s2, gf], hasRoundOne: false };
      }

      const qMatches: InternalMatch[] = [];
      if (numTeams === 8) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }
      const sMatches: InternalMatch[] = [];
      if (numTeams === 8) {
          sMatches.push({ id: 4, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, qMatches[0].teamA, qMatches[0].teamB), teamB: getWinnerTeam(1, qMatches[1].teamA, qMatches[1].teamB) });
          sMatches.push({ id: 5, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, qMatches[2].teamA, qMatches[2].teamB), teamB: getWinnerTeam(3, qMatches[3].teamA, qMatches[3].teamB) });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({ id: i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }
      const gfIndex = numTeams === 8 ? 6 : 2;
      const gf: InternalMatch = { id: gfIndex, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB), teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB) };
      return { roundOneMatches: [], quarterMatches: qMatches, semiMatches: sMatches, grandFinalMatch: gf, allMatches: [...qMatches, ...sMatches, gf], hasRoundOne: false };
  }, [match, scores, globalAssignments, getAssignedPlayer]); 

  const activeMatchData = useMemo(() => {
    const data = allMatches.find(m => m.id === currentMatchIdx);
    if (!data) return undefined;
    if (data.label === 'GRAND FINAL') {
        const sA = scores[`${currentMatchIdx}-A`] || 0;
        const sB = scores[`${currentMatchIdx}-B`] || 0;
        if ((sA + sB) % 2 !== 0) return { ...data, teamA: data.teamB, teamB: data.teamA };
    }
    return data;
  }, [allMatches, currentMatchIdx, scores]);

  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);
    setPhase('TRANSITION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let isSwapped = false;
     if (currentMatchIdx === grandFinalMatch.id) {
         const gamesPlayed = currentScoreA + currentScoreB;
         if (gamesPlayed % 2 !== 0) isSwapped = true;
     }
     let incrementA = 0; let incrementB = 0;
     if (currentRoundWinner === 'azure') { if (isSwapped) incrementB = 1; else incrementA = 1; } 
     else if (currentRoundWinner === 'crimson') { if (isSwapped) incrementA = 1; else incrementB = 1; }
     let newScoreA = currentScoreA + incrementA;
     let newScoreB = currentScoreB + incrementB;
     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));
     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const submitRename = () => {
    if (renameState.player && renameState.newName.trim()) {
        onUpdatePlayer({ ...renameState.player, name: renameState.newName.trim() });
        setRenameState({ isOpen: false, player: null, newName: '' });
    }
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reroll' && wheelState.winnerPlayer && activeMatchData) {
        const side = wheelState.team;
        const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
        const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
        if (teamIdx !== -1) {
            setGlobalAssignments(prev => ({ ...prev, [`${teamIdx}-${wheelState.role}`]: wheelState.winnerPlayer!.id }));
            onReroll(teamIdx, wheelState.role, wheelState.winnerPlayer!);
        }
    }
    setWheelState(null);
  };

  const handleStartGlobalReveal = () => {
     setIsGlobalRolling(true);
     match.teams.forEach((_, idx) => {
         setTimeout(() => {
             setRevealedTeamIndices(prev => new Set(prev).add(idx));
             if (idx === match.teams.length - 1) {
                 setTimeout(() => {
                     setIsGlobalRolling(false);
                     setIsGlobalRevealComplete(true);
                 }, 1500);
             }
         }, (idx + 1) * 2000); // Stagger reveal
     });
  };

  const renderPlayerCard = (role: Role, side: 'azure' | 'crimson') => {
    if (!activeMatchData) return null;
    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
    const player = teamData ? teamData.slots.find(s => s.role === role)?.player : null;
    const isCoach = role === Role.COACH;

    let theme = isCoach ? { bg: 'bg-[#1a1a1a]', border: 'border-white', glow: 'shadow-[0_0_20px_rgba(255,255,255,0.6)]', text: 'text-white', gradient: 'from-white/20 to-transparent' }
      : side === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' }
      : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#c02d2d]/20 to-transparent' };

    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group`}>
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${side === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${side === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {player?.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>

           <div className={`absolute top-2 z-50 flex gap-2 transition-all opacity-0 group-hover:opacity-100 ${side === 'azure' ? 'right-4' : 'left-4'}`}>
              <button onClick={(e) => { 
                  e.stopPropagation(); 
                  if (teamIdx !== -1) {
                      const usedIds = new Set(Object.values(globalAssignments));
                      const candidates = activePlayers.filter(p => !usedIds.has(p.id) && canPlay(p, role));
                      if (candidates.length > 0) {
                          const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
                          setWheelState({ isOpen: true, type: 'reroll', team: side, role, winnerName: newPlayer.name, winnerPlayer: newPlayer, candidates: candidates.map(p => p.name), duration: 4000 });
                      }
                  }
              }} className="p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full text-white hover:text-black transition-all" title="Reroll Player"><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
              <button onClick={(e) => { e.stopPropagation(); if(player) setRenameState({ isOpen: true, player, newName: player.name }); }} className="p-2.5 bg-black/60 hover:bg-[#00d2ff] rounded-full text-white hover:text-black transition-all" title="Change Nickname"><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
           </div>
        </div>
      </div>
    );
  };

  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" style={{ height: `${height}px`, ...style }}>
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b"><animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" /></stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%"><feGaussianBlur stdDeviation="3" result="blur"/><feComposite in="SourceGraphic" in2="blur" operator="over"/></filter>
          </defs>
          {type === 'fork' ? (
             <path d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} stroke="url(#energyLine)" strokeWidth="2.5" fill="none" filter="url(#energyGlow)" strokeLinecap="round" />
          ) : (
             <path d={`M 0,${height/2} L 100,${height/2}`} stroke="url(#energyLine)" strokeWidth="2.5" fill="none" filter="url(#energyGlow)" strokeLinecap="round" />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)"><animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} dur="2s" repeatCount="indefinite" /></circle>
          {type === 'fork' && (<circle r="3" fill="#fff" filter="url(#energyGlow)"><animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" /></circle>)}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: InternalMatch) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;
      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-md p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>
            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>
                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1"><div className="h-[1px] flex-1 bg-white"></div><span className="text-[8px] font-black italic text-[#8a9db8]">VS</span><div className="h-[1px] flex-1 bg-white"></div></div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>
            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-center">
                        <span className="text-[8px] text-[#dcb06b]/50 font-black uppercase tracking-widest">AUTO ADVANCE</span>
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => { const val = e.target.value.replace(/\D/g,'').slice(0,4); setMatchRoomIds(prev => ({ ...prev, [m.id]: val })); }} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----" />
                        </div>
                        {!isDone && m.teamA && m.teamB && <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">START</Button>}
                    </>
                )}
            </div>
        </div>
      );
  };

  const renderTeamRevealScreen = () => {
     return (
        <div className="fixed inset-0 z-[150] bg-[#05090f] overflow-y-auto custom-scrollbar flex flex-col items-center">
            {/* Background FX - Replicating Lobby Feel */}
            <div className="absolute inset-0 bg-[url('https://raw.githubusercontent.com/yoshiharuyamashita/css-fog-animation/master/img/fog1.png')] bg-repeat-x bg-cover opacity-10 animate-fog pointer-events-none"></div>
            <div className="absolute inset-0 bg-[url('https://raw.githubusercontent.com/yoshiharuyamashita/css-fog-animation/master/img/fog2.png')] bg-repeat-x bg-cover opacity-10 animate-fog pointer-events-none" style={{ animationDirection: 'reverse', animationDuration: '30s' }}></div>
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000000_100%)] pointer-events-none"></div>

            <div className="relative z-10 w-full max-w-[1600px] p-4 md:p-8 lg:p-12 flex flex-col items-center min-h-screen">

                {/* Header Section */}
                <div className="text-center mb-12 relative animate-slide-in">
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[120%] h-[120%] bg-[#dcb06b] blur-[120px] opacity-10 pointer-events-none"></div>
                    <h1 className="text-4xl md:text-6xl lg:text-7xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-[#f3dcb1] via-[#dcb06b] to-[#8a6d3b] tracking-[0.15em] drop-shadow-[0_0_30px_rgba(220,176,107,0.4)] mb-4">
                        OFFICIAL DRAFT
                    </h1>
                    <div className="flex items-center justify-center gap-6">
                         <div className="h-[1px] w-12 md:w-24 bg-gradient-to-r from-transparent to-[#dcb06b]"></div>
                         <p className="text-[#8a9db8] font-orbitron tracking-[0.4em] text-[10px] md:text-xs font-bold uppercase">TOURNAMENT ROSTER REVEAL</p>
                         <div className="h-[1px] w-12 md:w-24 bg-gradient-to-l from-transparent to-[#dcb06b]"></div>
                    </div>
                </div>

                {/* Team Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 w-full mb-32">
                    {match.teams.map((team, idx) => {
                        const isRevealed = revealedTeamIndices.has(idx);

                        return (
                            <div 
                                key={idx} 
                                className={`
                                    relative group transition-all duration-700
                                    ${isRevealed ? 'opacity-100 translate-y-0' : 'opacity-70 translate-y-4'}
                                `}
                            >
                                {/* Glow backing for revealed cards */}
                                {isRevealed && <div className="absolute -inset-1 bg-[#dcb06b] blur-lg opacity-20 group-hover:opacity-30 transition-opacity duration-500"></div>}

                                <div className={`
                                    relative bg-[#0a1a2f]/80 backdrop-blur-xl border 
                                    ${isRevealed ? 'border-[#dcb06b] shadow-[0_0_30px_rgba(220,176,107,0.15)]' : 'border-[#1e3a5f]'} 
                                    clip-corner-md p-1 h-full flex flex-col transition-colors duration-500
                                `}>
                                    {/* Scanning Line Animation if rolling */}
                                    {isGlobalRolling && !isRevealed && (
                                        <div className="absolute inset-0 z-20 overflow-hidden clip-corner-md pointer-events-none">
                                            <div className="w-full h-[2px] bg-[#00d2ff] shadow-[0_0_15px_#00d2ff] absolute top-0 animate-[scan_1.5s_linear_infinite]"></div>
                                            <div className="absolute inset-0 bg-gradient-to-b from-[#00d2ff]/10 to-transparent animate-[scan-gradient_1.5s_linear_infinite]"></div>
                                        </div>
                                    )}

                                    {/* Card Header */}
                                    <div className="bg-[#05090f]/80 p-4 border-b border-white/5 relative overflow-hidden group-hover:bg-[#05090f]/90 transition-colors">
                                        <div className="absolute top-0 right-0 p-2 opacity-10">
                                            <span className="text-[50px] font-black font-orbitron text-white leading-none tracking-tighter">{String(idx + 1).padStart(2, '0')}</span>
                                        </div>
                                        <div className="relative z-10 flex flex-col gap-1">
                                            <div className="flex items-center gap-3">
                                                <div className="w-1.5 h-8 shadow-[0_0_10px_currentColor]" style={{ backgroundColor: team.color, color: team.color }}></div>
                                                <h3 className="font-cinzel font-black text-white tracking-widest text-lg truncate drop-shadow-md">{team.name}</h3>
                                            </div>
                                            <div className={`text-[9px] font-orbitron font-bold tracking-wider uppercase pl-5 flex items-center gap-2 ${isRevealed ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>
                                                <div className={`w-1.5 h-1.5 rounded-full ${isRevealed ? 'bg-[#dcb06b] animate-pulse' : 'bg-[#4a5f78]'}`}></div>
                                                {isRevealed ? 'ROSTER CONFIRMED' : 'AWAITING DECRYPTION...'}
                                            </div>
                                        </div>
                                    </div>

                                    {/* Card Body (Roles) */}
                                    <div className="p-4 space-y-3 flex-1 bg-gradient-to-b from-[#0a1a2f]/40 to-[#05090f]/60">
                                        {ROLES_ORDER.map((role, rIdx) => {
                                            const player = getAssignedPlayer(idx, role);
                                            return (
                                                <div key={role} className="flex items-center gap-3 relative group/row">
                                                    {/* Role Icon */}
                                                    <div className={`
                                                        w-8 h-8 flex items-center justify-center rounded bg-[#05090f] border transition-colors duration-300
                                                        ${isRevealed ? 'border-[#dcb06b]/40 text-[#dcb06b] shadow-[0_0_10px_rgba(220,176,107,0.2)]' : 'border-[#1e3a5f] text-[#4a5f78]'}
                                                    `}>
                                                        <div className="scale-75">{RoleIcons[role]}</div>
                                                    </div>

                                                    {/* Player Name */}
                                                    <div className="flex-1 min-w-0 flex flex-col justify-center h-full">
                                                        <span className="text-[7px] text-[#4a5f78] uppercase font-bold tracking-wider leading-none mb-0.5">{role.replace(' Lane', '')}</span>
                                                        <div className={`
                                                            text-sm font-orbitron font-bold truncate transition-colors duration-300
                                                            ${isRevealed ? 'text-white drop-shadow-sm' : 'text-[#1e3a5f]'}
                                                        `}>
                                                            <ScrambleText text={player?.name || '???'} isRevealed={isRevealed} />
                                                        </div>
                                                    </div>

                                                    {/* Tech Decor */}
                                                    {isRevealed && (
                                                        <div className="opacity-0 group-hover/row:opacity-100 transition-opacity">
                                                            <div className="w-1 h-1 bg-[#dcb06b] rounded-full shadow-[0_0_5px_#dcb06b]"></div>
                                                        </div>
                                                    )}
                                                </div>
                                            );
                                        })}
                                    </div>

                                    {/* Card Footer */}
                                    <div className="h-1 w-full flex">
                                        <div className={`h-full flex-1 transition-all duration-1000 ${isRevealed ? 'bg-[#dcb06b] shadow-[0_0_10px_#dcb06b]' : 'bg-[#1e3a5f]'}`}></div>
                                        <div className="h-full w-4 bg-[#05090f]"></div>
                                        <div className={`h-full w-8 transition-all duration-1000 ${isRevealed ? 'bg-[#dcb06b]' : 'bg-[#1e3a5f]'}`}></div>
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>

                {/* Footer Controls */}
                <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-[#05090f] via-[#05090f]/95 to-transparent z-50 flex flex-col items-center pointer-events-none">
                    <div className="pointer-events-auto flex flex-col items-center gap-4">
                        {!isGlobalRevealComplete ? (
                            <button 
                                onClick={handleStartGlobalReveal} 
                                disabled={isGlobalRolling}
                                className={`
                                    group relative px-20 py-5 bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md 
                                    text-[#dcb06b] font-cinzel font-black text-xl tracking-[0.2em] 
                                    hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300
                                    ${isGlobalRolling ? 'opacity-50 cursor-not-allowed' : 'shadow-[0_0_30px_rgba(220,176,107,0.3)] hover:shadow-[0_0_50px_rgba(220,176,107,0.6)] animate-pulse'}
                                `}
                            >
                                <div className="absolute inset-0 bg-[#dcb06b] opacity-0 group-hover:opacity-10 transition-opacity"></div>
                                <span className="relative z-10 flex items-center gap-4">
                                    {isGlobalRolling ? (
                                        <>
                                            <svg className="animate-spin h-6 w-6" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                            DECRYPTING...
                                        </>
                                    ) : (
                                        <>COMMENCE REVEAL</>
                                    )}
                                </span>
                            </button>
                        ) : (
                            <button 
                                onClick={() => setPhase('OVERVIEW')} 
                                className="group relative px-24 py-6 bg-[#dcb06b] text-[#05090f] clip-corner-md font-cinzel font-black text-2xl tracking-[0.2em] hover:bg-white hover:scale-105 transition-all shadow-[0_0_50px_rgba(220,176,107,0.6)]"
                            >
                                ENTER BRACKET
                            </button>
                        )}

                        {!isGlobalRolling && !isGlobalRevealComplete && (
                            <button onClick={() => setPhase('OVERVIEW')} className="text-[#4a5f78] hover:text-[#dcb06b] text-[10px] font-orbitron font-bold uppercase tracking-widest border-b border-transparent hover:border-[#dcb06b] transition-all">
                                Skip Animation &gt;&gt;
                            </button>
                        )}
                    </div>
                </div>
            </div>

            <style>{`
                @keyframes scan {
                    0% { top: 0%; opacity: 0; }
                    10% { opacity: 1; }
                    90% { opacity: 1; }
                    100% { top: 100%; opacity: 0; }
                }
                @keyframes scan-gradient {
                    0% { top: -100%; }
                    100% { top: 100%; }
                }
            `}</style>
        </div>
     );
  };

  if (phase === 'TOURNAMENT_END') return (
      <div className="fixed inset-0 z-[300] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
        <div className="god-rays opacity-40"></div>
        <div className="relative z-20 flex flex-col items-center animate-trophy-pop w-full max-w-4xl">
            <h1 className="text-5xl md:text-8xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] mb-12 tracking-[0.2em] text-center px-4">TOURNAMENT CHAMPIONS</h1>
            <h2 className="text-6xl md:text-9xl font-black font-cinzel text-white text-center drop-shadow-[0_0_20px_#dcb06b] mb-12" style={{ color: tournamentChampion?.color }}>{tournamentChampion?.name}</h2>
            <Button onClick={onReset} size="lg" className="px-24 h-20 text-xl shadow-[0_0_50px_rgba(220,176,107,0.5)]">RETURN TO LOBBY</Button>
        </div>
      </div>
  );

  const overlayBackButton = (
      <div className="fixed top-6 left-6 z-[300]">
            <Button variant="outline" size="sm" onClick={onMinimize} className="bg-black/80 border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black">LOBBY</Button>
      </div>
  );

  if (phase === 'TEAM_REVEAL') return renderTeamRevealScreen();
  if (phase === 'TRANSITION' && activeMatchData) return <>{overlayBackButton}<PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} azureTeamName={activeMatchData.teamA?.name || 'TBD'} crimsonTeamName={activeMatchData.teamB?.name || 'TBD'} onComplete={() => setPhase('DECLARE_WIN')} /></>;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <>{overlayBackButton}<MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now(), azureTeamName: activeMatchData.teamA?.name, crimsonTeamName: activeMatchData.teamB?.name }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} /></>;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} azureTeamName={activeMatchData.teamA?.name} crimsonTeamName={activeMatchData.teamB?.name} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <>{overlayBackButton}<EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now(), azureTeamName: activeMatchData.teamA?.name, crimsonTeamName: activeMatchData.teamB?.name }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} /></>;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {/* Rename Modal UI */}
      {renameState.isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })}></div>
          <div className="relative w-full max-w-sm bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_30px_rgba(220,176,107,0.3)] animate-slide-in p-6">
            <h3 className="text-[#dcb06b] font-cinzel font-bold text-lg mb-4 text-center tracking-widest">CHANGE NICKNAME</h3>
            <input type="text" value={renameState.newName} onChange={e => setRenameState({ ...renameState, newName: e.target.value })} className="w-full bg-black/50 border border-[#1e3a5f] p-3 text-white font-orbitron focus:border-[#dcb06b] outline-none mb-6 text-center" autoFocus />
            <div className="flex gap-3">
              <Button variant="secondary" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })} className="flex-1">CANCEL</Button>
              <Button onClick={submitRename} className="flex-1">CONFIRM</Button>
            </div>
          </div>
        </div>
      )}

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="absolute top-8 left-8"><Button variant="outline" size="sm" onClick={onMinimize}>LOBBY</Button></div>
          <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-16 uppercase">TOURNAMENT BRACKET</h1>
          <div className="flex gap-16 md:gap-24 items-center justify-center relative py-20">
            {hasRoundOne && (<div className="flex flex-col gap-8 relative">{roundOneMatches.map((m, i) => (<div key={m.id} className="relative">{renderBracketMatchCard(m)}{i % 2 === 0 && <EnergyConnector type="fork" height={218} style={{top:'50%'}}/>}</div>))}</div>)}
            <div className="flex flex-col gap-32 relative">{quarterMatches.map((m, i) => (<div key={m.id} className="relative">{renderBracketMatchCard(m)}{i % 2 === 0 && <EnergyConnector type="fork" height={338} style={{top:'50%'}}/>}</div>))}</div>
            <div className="flex flex-col gap-64 relative">{semiMatches.map((m, i) => (<div key={m.id} className="relative">{renderBracketMatchCard(m)}{i === 0 && <EnergyConnector type="fork" height={458} style={{top:'50%'}}/>}</div>))}</div>
            <div className="relative scale-125 ml-10">{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={() => setShowAbortConfirm(true)} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState?.isOpen && <SpinWheel {...wheelState} roomId={activeRoomId} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')}>BACK TO BRACKET</Button>
                <div className="text-white font-orbitron font-black text-2xl tracking-[0.4em]">{activeRoomId}</div>
            </div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-32 items-end mb-6">
                    <div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-cyan-400">{activeMatchData?.teamA?.name}</h2></div>
                    <div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-red-500">{activeMatchData?.teamB?.name}</h2></div>
                </div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-32"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-10 left-0 right-0 flex justify-center">
                 <Button onClick={() => setPhase('TRANSITION')} size="lg">INITIALIZE BATTLE</Button>
            </div>
        </div>
      )}
      <ConfirmModal isOpen={showAbortConfirm} title="ABORT TOURNAMENT" message="End tournament?" onConfirm={onReset} onCancel={() => setShowAbortConfirm(false)} isDestructive />
    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';
import { ConfirmModal } from './ConfirmModal';
import { getFlexibleCandidate, canPlay, TBD_PLAYER } from '../utils/matchmaker';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  onMinimize: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
  onUpdatePlayer: (updatedPlayer: Player) => void;
}

interface InternalMatch {
    id: number;
    label: string;
    mode: string;
    teamA: any;
    teamB: any;
}

type BracketPhase = 'TEAM_REVEAL' | 'OVERVIEW' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

const ScrambleText: React.FC<{ text: string; isRevealed: boolean }> = ({ text, isRevealed }) => {
  const [display, setDisplay] = useState(isRevealed ? text : 'INITIALIZING...');

  useEffect(() => {
    if (!isRevealed) {
        const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789#@&";
        const interval = setInterval(() => {
            setDisplay(Array(text.length).fill(0).map(() => chars[Math.floor(Math.random() * chars.length)]).join(''));
        }, 50);
        return () => clearInterval(interval);
    } else {
        let iteration = 0;
        const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
        const interval = setInterval(() => {
            setDisplay(text.split("").map((letter, index) => {
                if (index < iteration) return letter;
                return chars[Math.floor(Math.random() * chars.length)];
            }).join(""));
            if (iteration >= text.length) clearInterval(interval);
            iteration += 1/2; 
        }, 30);
        return () => clearInterval(interval);
    }
  }, [text, isRevealed]);

  return <span>{display}</span>;
};

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, onMinimize, activePlayers, onReroll, onUpdatePlayer }) => {
  const [phase, setPhase] = useState<BracketPhase>('TEAM_REVEAL');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // Team Reveal State
  const [revealedTeamIndices, setRevealedTeamIndices] = useState<Set<number>>(new Set());
  const [isGlobalRolling, setIsGlobalRolling] = useState(false);
  const [isGlobalRevealComplete, setIsGlobalRevealComplete] = useState(false);

  const [globalAssignments, setGlobalAssignments] = useState<Record<string, string>>(() => {
      const initial: Record<string, string> = {};
      match.teams.forEach((team, tIdx) => {
          team.slots.forEach(slot => {
              if (slot.player && slot.player.id !== 'tbd') {
                  initial[`${tIdx}-${slot.role}`] = slot.player.id;
              }
          });
      });
      return initial;
  });

  useEffect(() => {
      setGlobalAssignments(prev => {
          const next = { ...prev };
          match.teams.forEach((team, tIdx) => {
              team.slots.forEach(slot => {
                  if (slot.player && slot.player.id !== 'tbd') {
                      next[`${tIdx}-${slot.role}`] = slot.player.id;
                  }
              });
          });
          return next;
      });
  }, [match]);

  const [showAbortConfirm, setShowAbortConfirm] = useState(false);
  const [renameState, setRenameState] = useState<{ isOpen: boolean; player: Player | null; newName: string }>({
    isOpen: false,
    player: null,
    newName: ''
  });

  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  const getAssignedPlayer = useCallback((teamIdx: number, role: Role): Player => {
      const key = `${teamIdx}-${role}`;
      const pid = globalAssignments[key];
      if (pid) {
          return activePlayers.find(p => p.id === pid) || TBD_PLAYER;
      }
      return TBD_PLAYER;
  }, [globalAssignments, activePlayers]);

  const { roundOneMatches, quarterMatches, semiMatches, grandFinalMatch, allMatches, hasRoundOne } = useMemo(() => {
      const getTeamObj = (teamIndex: number) => {
          if (teamIndex < 0 || teamIndex >= match.teams.length) return null;
          const original = match.teams[teamIndex];
          const updatedSlots = original.slots.map(s => ({
              ...s,
              player: getAssignedPlayer(teamIndex, s.role)
          }));
          return { ...original, slots: updatedSlots };
      };

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const numTeams = match.teams.length;

      // Logika khusus 12 Tim
      if (numTeams === 12) {
          const r1: InternalMatch[] = [];
          for (let i = 0; i < 4; i++) {
              r1.push({ id: i, label: `PLAY-IN ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
          const qm: InternalMatch[] = [];
          qm.push({ id: 4, label: 'QUARTER 1', mode: 'BO1', teamA: getWinnerTeam(0, r1[0].teamA, r1[0].teamB), teamB: getTeamObj(8) });
          qm.push({ id: 5, label: 'QUARTER 2', mode: 'BO1', teamA: getWinnerTeam(1, r1[1].teamA, r1[1].teamB), teamB: getTeamObj(9) });
          qm.push({ id: 6, label: 'QUARTER 3', mode: 'BO1', teamA: getWinnerTeam(2, r1[2].teamA, r1[2].teamB), teamB: getTeamObj(10) });
          qm.push({ id: 7, label: 'QUARTER 4', mode: 'BO1', teamA: getWinnerTeam(3, r1[3].teamA, r1[3].teamB), teamB: getTeamObj(11) });

          const sm: InternalMatch[] = [];
          sm.push({ id: 8, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(4, qm[0].teamA, qm[0].teamB), teamB: getWinnerTeam(5, qm[1].teamA, qm[1].teamB) });
          sm.push({ id: 9, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(6, qm[2].teamA, qm[2].teamB), teamB: getWinnerTeam(7, qm[3].teamA, qm[3].teamB) });

          const gf: InternalMatch = { id: 10, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(8, sm[0].teamA, sm[0].teamB), teamB: getWinnerTeam(9, sm[1].teamA, sm[1].teamB) };

          return { roundOneMatches: r1, quarterMatches: qm, semiMatches: sm, grandFinalMatch: gf, allMatches: [...r1, ...qm, ...sm, gf], hasRoundOne: true };
      }

      // Existing logics for 3, 4, 5, 6, 8 teams...
      if (numTeams === 3) {
        const m0: InternalMatch = { id: 0, label: 'ELIMINATION', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const m1: InternalMatch = { id: 1, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(0, m0.teamA, m0.teamB), teamB: getTeamObj(2) };
        const m2: InternalMatch = { id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, m0.teamA, m0.teamB), teamB: getWinnerTeam(1, m1.teamA, m1.teamB) };
        const matches: InternalMatch[] = [m0, m1, m2];
        return { roundOneMatches: [], quarterMatches: [], semiMatches: [m0, m1], grandFinalMatch: m2, allMatches: matches, hasRoundOne: false };
      }

      if (numTeams === 5 || numTeams === 6) {
        const q0: InternalMatch = { id: 0, label: 'QUARTER 1', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const q1: InternalMatch = { id: 1, label: 'QUARTER 2', mode: 'BO1', teamA: getTeamObj(2), teamB: getTeamObj(3) };
        const q2: InternalMatch = { id: 2, label: 'QUARTER 3', mode: 'BO1', teamA: getTeamObj(4), teamB: getTeamObj(5) || null };
        const s1: InternalMatch = { id: 3, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, q0.teamA, q0.teamB), teamB: getWinnerTeam(1, q1.teamA, q1.teamB) };
        const s2: InternalMatch = { id: 4, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, q2.teamA, q2.teamB), teamB: getLoserTeam(3, s1.teamA, s1.teamB) };
        const gf: InternalMatch = { id: 5, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(3, s1.teamA, s1.teamB), teamB: getWinnerTeam(4, s2.teamA, s2.teamB) };
        return { roundOneMatches: [], quarterMatches: [q0, q1, q2], semiMatches: [s1, s2], grandFinalMatch: gf, allMatches: [q0, q1, q2, s1, s2, gf], hasRoundOne: false };
      }

      const qMatches: InternalMatch[] = [];
      if (numTeams === 8) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }
      const sMatches: InternalMatch[] = [];
      if (numTeams === 8) {
          sMatches.push({ id: 4, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, qMatches[0].teamA, qMatches[0].teamB), teamB: getWinnerTeam(1, qMatches[1].teamA, qMatches[1].teamB) });
          sMatches.push({ id: 5, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, qMatches[2].teamA, qMatches[2].teamB), teamB: getWinnerTeam(3, qMatches[3].teamA, qMatches[3].teamB) });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({ id: i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }
      const gfIndex = numTeams === 8 ? 6 : 2;
      const gf: InternalMatch = { id: gfIndex, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB), teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB) };
      return { roundOneMatches: [], quarterMatches: qMatches, semiMatches: sMatches, grandFinalMatch: gf, allMatches: [...qMatches, ...sMatches, gf], hasRoundOne: false };
  }, [match, scores, globalAssignments, getAssignedPlayer]); 

  const activeMatchData = useMemo(() => {
    const data = allMatches.find(m => m.id === currentMatchIdx);
    if (!data) return undefined;
    if (data.label === 'GRAND FINAL') {
        const sA = scores[`${currentMatchIdx}-A`] || 0;
        const sB = scores[`${currentMatchIdx}-B`] || 0;
        if ((sA + sB) % 2 !== 0) return { ...data, teamA: data.teamB, teamB: data.teamA };
    }
    return data;
  }, [allMatches, currentMatchIdx, scores]);

  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);
    setPhase('TRANSITION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let isSwapped = false;
     if (currentMatchIdx === grandFinalMatch.id) {
         const gamesPlayed = currentScoreA + currentScoreB;
         if (gamesPlayed % 2 !== 0) isSwapped = true;
     }
     let incrementA = 0; let incrementB = 0;
     if (currentRoundWinner === 'azure') { if (isSwapped) incrementB = 1; else incrementA = 1; } 
     else if (currentRoundWinner === 'crimson') { if (isSwapped) incrementA = 1; else incrementB = 1; }
     let newScoreA = currentScoreA + incrementA;
     let newScoreB = currentScoreB + incrementB;
     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));
     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const submitRename = () => {
    if (renameState.player && renameState.newName.trim()) {
        onUpdatePlayer({ ...renameState.player, name: renameState.newName.trim() });
        setRenameState({ isOpen: false, player: null, newName: '' });
    }
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reroll' && wheelState.winnerPlayer && activeMatchData) {
        const side = wheelState.team;
        const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
        const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
        if (teamIdx !== -1) {
            setGlobalAssignments(prev => ({ ...prev, [`${teamIdx}-${wheelState.role}`]: wheelState.winnerPlayer!.id }));
            onReroll(teamIdx, wheelState.role, wheelState.winnerPlayer!);
        }
    }
    setWheelState(null);
  };

  const handleStartGlobalReveal = () => {
     setIsGlobalRolling(true);
     match.teams.forEach((_, idx) => {
         setTimeout(() => {
             setRevealedTeamIndices(prev => new Set(prev).add(idx));
             if (idx === match.teams.length - 1) {
                 setTimeout(() => {
                     setIsGlobalRolling(false);
                     setIsGlobalRevealComplete(true);
                 }, 1500);
             }
         }, (idx + 1) * 2000); // Stagger reveal
     });
  };

  const renderPlayerCard = (role: Role, side: 'azure' | 'crimson') => {
    if (!activeMatchData) return null;
    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
    const player = teamData ? teamData.slots.find(s => s.role === role)?.player : null;
    const isCoach = role === Role.COACH;

    let theme = isCoach ? { bg: 'bg-[#1a1a1a]', border: 'border-white', glow: 'shadow-[0_0_20px_rgba(255,255,255,0.6)]', text: 'text-white', gradient: 'from-white/20 to-transparent' }
      : side === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' }
      : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#c02d2d]/20 to-transparent' };

    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group`}>
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${side === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${side === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {player?.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>

           <div className={`absolute top-2 z-50 flex gap-2 transition-all opacity-0 group-hover:opacity-100 ${side === 'azure' ? 'right-4' : 'left-4'}`}>
              <button onClick={(e) => { 
                  e.stopPropagation(); 
                  if (teamIdx !== -1) {
                      const usedIds = new Set(Object.values(globalAssignments));
                      const candidates = activePlayers.filter(p => !usedIds.has(p.id) && canPlay(p, role));
                      if (candidates.length > 0) {
                          const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
                          setWheelState({ isOpen: true, type: 'reroll', team: side, role, winnerName: newPlayer.name, winnerPlayer: newPlayer, candidates: candidates.map(p => p.name), duration: 4000 });
                      }
                  }
              }} className="p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full text-white hover:text-black transition-all" title="Reroll Player"><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
              <button onClick={(e) => { e.stopPropagation(); if(player) setRenameState({ isOpen: true, player, newName: player.name }); }} className="p-2.5 bg-black/60 hover:bg-[#00d2ff] rounded-full text-white hover:text-black transition-all" title="Change Nickname"><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
           </div>
        </div>
      </div>
    );
  };

  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" style={{ height: `${height}px`, ...style }}>
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b"><animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" /></stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%"><feGaussianBlur stdDeviation="3" result="blur"/><feComposite in="SourceGraphic" in2="blur" operator="over"/></filter>
          </defs>
          {type === 'fork' ? (
             <path d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} stroke="url(#energyLine)" strokeWidth="2.5" fill="none" filter="url(#energyGlow)" strokeLinecap="round" />
          ) : (
             <path d={`M 0,${height/2} L 100,${height/2}`} stroke="url(#energyLine)" strokeWidth="2.5" fill="none" filter="url(#energyGlow)" strokeLinecap="round" />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)"><animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} dur="2s" repeatCount="indefinite" /></circle>
          {type === 'fork' && (<circle r="3" fill="#fff" filter="url(#energyGlow)"><animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" /></circle>)}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: InternalMatch) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;
      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-md p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>
            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>
                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1"><div className="h-[1px] flex-1 bg-white"></div><span className="text-[8px] font-black italic text-[#8a9db8]">VS</span><div className="h-[1px] flex-1 bg-white"></div></div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>
            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-center">
                        <span className="text-[8px] text-[#dcb06b]/50 font-black uppercase tracking-widest">AUTO ADVANCE</span>
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => { const val = e.target.value.replace(/\D/g,'').slice(0,4); setMatchRoomIds(prev => ({ ...prev, [m.id]: val })); }} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----" />
                        </div>
                        {!isDone && m.teamA && m.teamB && <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">START</Button>}
                    </>
                )}
            </div>
        </div>
      );
  };

  const renderTeamRevealScreen = () => {
     return (
        <div className="fixed inset-0 z-[150] bg-[#05090f] overflow-y-auto custom-scrollbar flex flex-col items-center">
            {/* Background FX - Replicating Lobby Feel */}
            <div className="absolute inset-0 bg-[url('https://raw.githubusercontent.com/yoshiharuyamashita/css-fog-animation/master/img/fog1.png')] bg-repeat-x bg-cover opacity-10 animate-fog pointer-events-none"></div>
            <div className="absolute inset-0 bg-[url('https://raw.githubusercontent.com/yoshiharuyamashita/css-fog-animation/master/img/fog2.png')] bg-repeat-x bg-cover opacity-10 animate-fog pointer-events-none" style={{ animationDirection: 'reverse', animationDuration: '30s' }}></div>
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000000_100%)] pointer-events-none"></div>

            <div className="relative z-10 w-full max-w-[1600px] p-4 md:p-8 lg:p-12 flex flex-col items-center min-h-screen">

                {/* Header Section */}
                <div className="text-center mb-12 relative animate-slide-in">
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[120%] h-[120%] bg-[#dcb06b] blur-[120px] opacity-10 pointer-events-none"></div>
                    <h1 className="text-4xl md:text-6xl lg:text-7xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-[#f3dcb1] via-[#dcb06b] to-[#8a6d3b] tracking-[0.15em] drop-shadow-[0_0_30px_rgba(220,176,107,0.4)] mb-4">
                        OFFICIAL DRAFT
                    </h1>
                    <div className="flex items-center justify-center gap-6">
                         <div className="h-[1px] w-12 md:w-24 bg-gradient-to-r from-transparent to-[#dcb06b]"></div>
                         <p className="text-[#8a9db8] font-orbitron tracking-[0.4em] text-[10px] md:text-xs font-bold uppercase">TOURNAMENT ROSTER REVEAL</p>
                         <div className="h-[1px] w-12 md:w-24 bg-gradient-to-l from-transparent to-[#dcb06b]"></div>
                    </div>
                </div>

                {/* Team Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 w-full mb-32">
                    {match.teams.map((team, idx) => {
                        const isRevealed = revealedTeamIndices.has(idx);

                        return (
                            <div 
                                key={idx} 
                                className={`
                                    relative group transition-all duration-700
                                    ${isRevealed ? 'opacity-100 translate-y-0' : 'opacity-70 translate-y-4'}
                                `}
                            >
                                {/* Glow backing for revealed cards */}
                                {isRevealed && <div className="absolute -inset-1 bg-[#dcb06b] blur-lg opacity-20 group-hover:opacity-30 transition-opacity duration-500"></div>}

                                <div className={`
                                    relative bg-[#0a1a2f]/80 backdrop-blur-xl border 
                                    ${isRevealed ? 'border-[#dcb06b] shadow-[0_0_30px_rgba(220,176,107,0.15)]' : 'border-[#1e3a5f]'} 
                                    clip-corner-md p-1 h-full flex flex-col transition-colors duration-500
                                `}>
                                    {/* Scanning Line Animation if rolling */}
                                    {isGlobalRolling && !isRevealed && (
                                        <div className="absolute inset-0 z-20 overflow-hidden clip-corner-md pointer-events-none">
                                            <div className="w-full h-[2px] bg-[#00d2ff] shadow-[0_0_15px_#00d2ff] absolute top-0 animate-[scan_1.5s_linear_infinite]"></div>
                                            <div className="absolute inset-0 bg-gradient-to-b from-[#00d2ff]/10 to-transparent animate-[scan-gradient_1.5s_linear_infinite]"></div>
                                        </div>
                                    )}

                                    {/* Card Header */}
                                    <div className="bg-[#05090f]/80 p-4 border-b border-white/5 relative overflow-hidden group-hover:bg-[#05090f]/90 transition-colors">
                                        <div className="absolute top-0 right-0 p-2 opacity-10">
                                            <span className="text-[50px] font-black font-orbitron text-white leading-none tracking-tighter">{String(idx + 1).padStart(2, '0')}</span>
                                        </div>
                                        <div className="relative z-10 flex flex-col gap-1">
                                            <div className="flex items-center gap-3">
                                                <div className="w-1.5 h-8 shadow-[0_0_10px_currentColor]" style={{ backgroundColor: team.color, color: team.color }}></div>
                                                <h3 className="font-cinzel font-black text-white tracking-widest text-lg truncate drop-shadow-md">{team.name}</h3>
                                            </div>
                                            <div className={`text-[9px] font-orbitron font-bold tracking-wider uppercase pl-5 flex items-center gap-2 ${isRevealed ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>
                                                <div className={`w-1.5 h-1.5 rounded-full ${isRevealed ? 'bg-[#dcb06b] animate-pulse' : 'bg-[#4a5f78]'}`}></div>
                                                {isRevealed ? 'ROSTER CONFIRMED' : 'AWAITING DECRYPTION...'}
                                            </div>
                                        </div>
                                    </div>

                                    {/* Card Body (Roles) */}
                                    <div className="p-4 space-y-3 flex-1 bg-gradient-to-b from-[#0a1a2f]/40 to-[#05090f]/60">
                                        {ROLES_ORDER.map((role, rIdx) => {
                                            const player = getAssignedPlayer(idx, role);
                                            return (
                                                <div key={role} className="flex items-center gap-3 relative group/row">
                                                    {/* Role Icon */}
                                                    <div className={`
                                                        w-8 h-8 flex items-center justify-center rounded bg-[#05090f] border transition-colors duration-300
                                                        ${isRevealed ? 'border-[#dcb06b]/40 text-[#dcb06b] shadow-[0_0_10px_rgba(220,176,107,0.2)]' : 'border-[#1e3a5f] text-[#4a5f78]'}
                                                    `}>
                                                        <div className="scale-75">{RoleIcons[role]}</div>
                                                    </div>

                                                    {/* Player Name */}
                                                    <div className="flex-1 min-w-0 flex flex-col justify-center h-full">
                                                        <span className="text-[7px] text-[#4a5f78] uppercase font-bold tracking-wider leading-none mb-0.5">{role.replace(' Lane', '')}</span>
                                                        <div className={`
                                                            text-sm font-orbitron font-bold truncate transition-colors duration-300
                                                            ${isRevealed ? 'text-white drop-shadow-sm' : 'text-[#1e3a5f]'}
                                                        `}>
                                                            <ScrambleText text={player?.name || '???'} isRevealed={isRevealed} />
                                                        </div>
                                                    </div>

                                                    {/* Tech Decor */}
                                                    {isRevealed && (
                                                        <div className="opacity-0 group-hover/row:opacity-100 transition-opacity">
                                                            <div className="w-1 h-1 bg-[#dcb06b] rounded-full shadow-[0_0_5px_#dcb06b]"></div>
                                                        </div>
                                                    )}
                                                </div>
                                            );
                                        })}
                                    </div>

                                    {/* Card Footer */}
                                    <div className="h-1 w-full flex">
                                        <div className={`h-full flex-1 transition-all duration-1000 ${isRevealed ? 'bg-[#dcb06b] shadow-[0_0_10px_#dcb06b]' : 'bg-[#1e3a5f]'}`}></div>
                                        <div className="h-full w-4 bg-[#05090f]"></div>
                                        <div className={`h-full w-8 transition-all duration-1000 ${isRevealed ? 'bg-[#dcb06b]' : 'bg-[#1e3a5f]'}`}></div>
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>

                {/* Footer Controls */}
                <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-[#05090f] via-[#05090f]/95 to-transparent z-50 flex flex-col items-center pointer-events-none">
                    <div className="pointer-events-auto flex flex-col items-center gap-4">
                        {!isGlobalRevealComplete ? (
                            <button 
                                onClick={handleStartGlobalReveal} 
                                disabled={isGlobalRolling}
                                className={`
                                    group relative px-20 py-5 bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md 
                                    text-[#dcb06b] font-cinzel font-black text-xl tracking-[0.2em] 
                                    hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300
                                    ${isGlobalRolling ? 'opacity-50 cursor-not-allowed' : 'shadow-[0_0_30px_rgba(220,176,107,0.3)] hover:shadow-[0_0_50px_rgba(220,176,107,0.6)] animate-pulse'}
                                `}
                            >
                                <div className="absolute inset-0 bg-[#dcb06b] opacity-0 group-hover:opacity-10 transition-opacity"></div>
                                <span className="relative z-10 flex items-center gap-4">
                                    {isGlobalRolling ? (
                                        <>
                                            <svg className="animate-spin h-6 w-6" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                            DECRYPTING...
                                        </>
                                    ) : (
                                        <>COMMENCE REVEAL</>
                                    )}
                                </span>
                            </button>
                        ) : (
                            <button 
                                onClick={() => setPhase('OVERVIEW')} 
                                className="group relative px-24 py-6 bg-[#dcb06b] text-[#05090f] clip-corner-md font-cinzel font-black text-2xl tracking-[0.2em] hover:bg-white hover:scale-105 transition-all shadow-[0_0_50px_rgba(220,176,107,0.6)]"
                            >
                                ENTER BRACKET
                            </button>
                        )}

                        {!isGlobalRolling && !isGlobalRevealComplete && (
                            <button onClick={() => setPhase('OVERVIEW')} className="text-[#4a5f78] hover:text-[#dcb06b] text-[10px] font-orbitron font-bold uppercase tracking-widest border-b border-transparent hover:border-[#dcb06b] transition-all">
                                Skip Animation &gt;&gt;
                            </button>
                        )}
                    </div>
                </div>
            </div>

            <style>{`
                @keyframes scan {
                    0% { top: 0%; opacity: 0; }
                    10% { opacity: 1; }
                    90% { opacity: 1; }
                    100% { top: 100%; opacity: 0; }
                }
                @keyframes scan-gradient {
                    0% { top: -100%; }
                    100% { top: 100%; }
                }
            `}</style>
        </div>
     );
  };

  if (phase === 'TOURNAMENT_END') return (
      <div className="fixed inset-0 z-[300] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
        <div className="god-rays opacity-40"></div>
        <div className="relative z-20 flex flex-col items-center animate-trophy-pop w-full max-w-4xl">
            <h1 className="text-5xl md:text-8xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] mb-12 tracking-[0.2em] text-center px-4">TOURNAMENT CHAMPIONS</h1>
            <h2 className="text-6xl md:text-9xl font-black font-cinzel text-white text-center drop-shadow-[0_0_20px_#dcb06b] mb-12" style={{ color: tournamentChampion?.color }}>{tournamentChampion?.name}</h2>
            <Button onClick={onReset} size="lg" className="px-24 h-20 text-xl shadow-[0_0_50px_rgba(220,176,107,0.5)]">RETURN TO LOBBY</Button>
        </div>
      </div>
  );

  const overlayBackButton = (
      <div className="fixed top-6 left-6 z-[300]">
            <Button variant="outline" size="sm" onClick={onMinimize} className="bg-black/80 border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black">LOBBY</Button>
      </div>
  );

  if (phase === 'TEAM_REVEAL') return renderTeamRevealScreen();
  if (phase === 'TRANSITION' && activeMatchData) return <>{overlayBackButton}<PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} azureTeamName={activeMatchData.teamA?.name || 'TBD'} crimsonTeamName={activeMatchData.teamB?.name || 'TBD'} onComplete={() => setPhase('DECLARE_WIN')} /></>;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <>{overlayBackButton}<MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now(), azureTeamName: activeMatchData.teamA?.name, crimsonTeamName: activeMatchData.teamB?.name }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} /></>;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} azureTeamName={activeMatchData.teamA?.name} crimsonTeamName={activeMatchData.teamB?.name} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <>{overlayBackButton}<EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now(), azureTeamName: activeMatchData.teamA?.name, crimsonTeamName: activeMatchData.teamB?.name }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} /></>;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {/* Rename Modal UI */}
      {renameState.isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })}></div>
          <div className="relative w-full max-w-sm bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_30px_rgba(220,176,107,0.3)] animate-slide-in p-6">
            <h3 className="text-[#dcb06b] font-cinzel font-bold text-lg mb-4 text-center tracking-widest">CHANGE NICKNAME</h3>
            <input type="text" value={renameState.newName} onChange={e => setRenameState({ ...renameState, newName: e.target.value })} className="w-full bg-black/50 border border-[#1e3a5f] p-3 text-white font-orbitron focus:border-[#dcb06b] outline-none mb-6 text-center" autoFocus />
            <div className="flex gap-3">
              <Button variant="secondary" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })} className="flex-1">CANCEL</Button>
              <Button onClick={submitRename} className="flex-1">CONFIRM</Button>
            </div>
          </div>
        </div>
      )}

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="absolute top-8 left-8"><Button variant="outline" size="sm" onClick={onMinimize}>LOBBY</Button></div>
          <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-16 uppercase">TOURNAMENT BRACKET</h1>
          <div className="flex gap-16 md:gap-24 items-center justify-center relative py-20">
            {hasRoundOne && (<div className="flex flex-col gap-8 relative">{roundOneMatches.map((m, i) => (<div key={m.id} className="relative">{renderBracketMatchCard(m)}{i % 2 === 0 && <EnergyConnector type="fork" height={218} style={{top:'50%'}}/>}</div>))}</div>)}
            <div className="flex flex-col gap-32 relative">{quarterMatches.map((m, i) => (<div key={m.id} className="relative">{renderBracketMatchCard(m)}{i % 2 === 0 && <EnergyConnector type="fork" height={338} style={{top:'50%'}}/>}</div>))}</div>
            <div className="flex flex-col gap-64 relative">{semiMatches.map((m, i) => (<div key={m.id} className="relative">{renderBracketMatchCard(m)}{i === 0 && <EnergyConnector type="fork" height={458} style={{top:'50%'}}/>}</div>))}</div>
            <div className="relative scale-125 ml-10">{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={() => setShowAbortConfirm(true)} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState?.isOpen && <SpinWheel {...wheelState} roleName={wheelState.role} roomId={activeRoomId} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')}>BACK TO BRACKET</Button>
                <div className="text-white font-orbitron font-black text-2xl tracking-[0.4em]">{activeRoomId}</div>
            </div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-32 items-end mb-6">
                    <div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-cyan-400">{activeMatchData?.teamA?.name}</h2></div>
                    <div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-red-500">{activeMatchData?.teamB?.name}</h2></div>
                </div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-32"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-10 left-0 right-0 flex justify-center">
                 <Button onClick={() => setPhase('TRANSITION')} size="lg">INITIALIZE BATTLE</Button>
            </div>
        </div>
      )}
      <ConfirmModal isOpen={showAbortConfirm} title="ABORT TOURNAMENT" message="End tournament?" onConfirm={onReset} onCancel={() => setShowAbortConfirm(false)} isDestructive />
    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';
import { ConfirmModal } from './ConfirmModal';
import { getFlexibleCandidate, canPlay, TBD_PLAYER } from '../utils/matchmaker';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  onMinimize: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
  onUpdatePlayer: (updatedPlayer: Player) => void;
}

interface InternalMatch {
    id: number;
    label: string;
    mode: string;
    teamA: any;
    teamB: any;
}

type BracketPhase = 'TEAM_REVEAL' | 'OVERVIEW' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

const ScrambleText: React.FC<{ text: string; isRevealed: boolean }> = ({ text, isRevealed }) => {
  const [display, setDisplay] = useState(isRevealed ? text : 'INITIALIZING...');

  useEffect(() => {
    if (!isRevealed) {
        const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789#@&";
        const interval = setInterval(() => {
            setDisplay(Array(text.length).fill(0).map(() => chars[Math.floor(Math.random() * chars.length)]).join(''));
        }, 50);
        return () => clearInterval(interval);
    } else {
        let iteration = 0;
        const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
        const interval = setInterval(() => {
            setDisplay(text.split("").map((letter, index) => {
                if (index < iteration) return letter;
                return chars[Math.floor(Math.random() * chars.length)];
            }).join(""));
            if (iteration >= text.length) clearInterval(interval);
            iteration += 1/2; 
        }, 30);
        return () => clearInterval(interval);
    }
  }, [text, isRevealed]);

  return <span>{display}</span>;
};

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, onMinimize, activePlayers, onReroll, onUpdatePlayer }) => {
  const [phase, setPhase] = useState<BracketPhase>('TEAM_REVEAL');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // Team Reveal State
  const [revealedTeamIndices, setRevealedTeamIndices] = useState<Set<number>>(new Set());
  const [isGlobalRolling, setIsGlobalRolling] = useState(false);
  const [isGlobalRevealComplete, setIsGlobalRevealComplete] = useState(false);

  const [globalAssignments, setGlobalAssignments] = useState<Record<string, string>>(() => {
      const initial: Record<string, string> = {};
      match.teams.forEach((team, tIdx) => {
          team.slots.forEach(slot => {
              if (slot.player && slot.player.id !== 'tbd') {
                  initial[`${tIdx}-${slot.role}`] = slot.player.id;
              }
          });
      });
      return initial;
  });

  useEffect(() => {
      setGlobalAssignments(prev => {
          const next = { ...prev };
          match.teams.forEach((team, tIdx) => {
              team.slots.forEach(slot => {
                  if (slot.player && slot.player.id !== 'tbd') {
                      next[`${tIdx}-${slot.role}`] = slot.player.id;
                  }
              });
          });
          return next;
      });
  }, [match]);

  const [showAbortConfirm, setShowAbortConfirm] = useState(false);
  const [renameState, setRenameState] = useState<{ isOpen: boolean; player: Player | null; newName: string }>({
    isOpen: false,
    player: null,
    newName: ''
  });

  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  const getAssignedPlayer = useCallback((teamIdx: number, role: Role): Player => {
      const key = `${teamIdx}-${role}`;
      const pid = globalAssignments[key];
      if (pid) {
          return activePlayers.find(p => p.id === pid) || TBD_PLAYER;
      }
      return TBD_PLAYER;
  }, [globalAssignments, activePlayers]);

  const { roundOneMatches, quarterMatches, semiMatches, grandFinalMatch, allMatches, hasRoundOne } = useMemo(() => {
      const getTeamObj = (teamIndex: number) => {
          if (teamIndex < 0 || teamIndex >= match.teams.length) return null;
          const original = match.teams[teamIndex];
          const updatedSlots = original.slots.map(s => ({
              ...s,
              player: getAssignedPlayer(teamIndex, s.role)
          }));
          return { ...original, slots: updatedSlots };
      };

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const numTeams = match.teams.length;

      // Logika khusus 12 Tim
      if (numTeams === 12) {
          const r1: InternalMatch[] = [];
          for (let i = 0; i < 4; i++) {
              r1.push({ id: i, label: `PLAY-IN ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
          const qm: InternalMatch[] = [];
          qm.push({ id: 4, label: 'QUARTER 1', mode: 'BO1', teamA: getWinnerTeam(0, r1[0].teamA, r1[0].teamB), teamB: getTeamObj(8) });
          qm.push({ id: 5, label: 'QUARTER 2', mode: 'BO1', teamA: getWinnerTeam(1, r1[1].teamA, r1[1].teamB), teamB: getTeamObj(9) });
          qm.push({ id: 6, label: 'QUARTER 3', mode: 'BO1', teamA: getWinnerTeam(2, r1[2].teamA, r1[2].teamB), teamB: getTeamObj(10) });
          qm.push({ id: 7, label: 'QUARTER 4', mode: 'BO1', teamA: getWinnerTeam(3, r1[3].teamA, r1[3].teamB), teamB: getTeamObj(11) });

          const sm: InternalMatch[] = [];
          sm.push({ id: 8, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(4, qm[0].teamA, qm[0].teamB), teamB: getWinnerTeam(5, qm[1].teamA, qm[1].teamB) });
          sm.push({ id: 9, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(6, qm[2].teamA, qm[2].teamB), teamB: getWinnerTeam(7, qm[3].teamA, qm[3].teamB) });

          const gf: InternalMatch = { id: 10, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(8, sm[0].teamA, sm[0].teamB), teamB: getWinnerTeam(9, sm[1].teamA, sm[1].teamB) };

          return { roundOneMatches: r1, quarterMatches: qm, semiMatches: sm, grandFinalMatch: gf, allMatches: [...r1, ...qm, ...sm, gf], hasRoundOne: true };
      }

      // Logika khusus 16 Tim
      if (numTeams === 16) {
          const r16: InternalMatch[] = [];
          for (let i = 0; i < 8; i++) {
              r16.push({ id: i, label: `R16 - MATCH ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
          const qm: InternalMatch[] = [];
          for (let i = 0; i < 4; i++) {
              qm.push({ id: 8+i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: getWinnerTeam(i*2, r16[i*2].teamA, r16[i*2].teamB), teamB: getWinnerTeam(i*2+1, r16[i*2+1].teamA, r16[i*2+1].teamB) });
          }
          const sm: InternalMatch[] = [];
          for (let i = 0; i < 2; i++) {
              sm.push({ id: 12+i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: getWinnerTeam(8+i*2, qm[i*2].teamA, qm[i*2].teamB), teamB: getWinnerTeam(8+i*2+1, qm[i*2+1].teamA, qm[i*2+1].teamB) });
          }
          const gf: InternalMatch = { id: 14, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(12, sm[0].teamA, sm[0].teamB), teamB: getWinnerTeam(13, sm[1].teamA, sm[1].teamB) };

          return { roundOneMatches: r16, quarterMatches: qm, semiMatches: sm, grandFinalMatch: gf, allMatches: [...r16, ...qm, ...sm, gf], hasRoundOne: true };
      }

      // Existing logics for 3, 4, 5, 6, 8 teams...
      if (numTeams === 3) {
        const m0: InternalMatch = { id: 0, label: 'ELIMINATION', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const m1: InternalMatch = { id: 1, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(0, m0.teamA, m0.teamB), teamB: getTeamObj(2) };
        const m2: InternalMatch = { id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, m0.teamA, m0.teamB), teamB: getWinnerTeam(1, m1.teamA, m1.teamB) };
        const matches: InternalMatch[] = [m0, m1, m2];
        return { roundOneMatches: [], quarterMatches: [], semiMatches: [m0, m1], grandFinalMatch: m2, allMatches: matches, hasRoundOne: false };
      }

      if (numTeams === 5 || numTeams === 6) {
        const q0: InternalMatch = { id: 0, label: 'QUARTER 1', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const q1: InternalMatch = { id: 1, label: 'QUARTER 2', mode: 'BO1', teamA: getTeamObj(2), teamB: getTeamObj(3) };
        const q2: InternalMatch = { id: 2, label: 'QUARTER 3', mode: 'BO1', teamA: getTeamObj(4), teamB: getTeamObj(5) || null };
        const s1: InternalMatch = { id: 3, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, q0.teamA, q0.teamB), teamB: getWinnerTeam(1, q1.teamA, q1.teamB) };
        const s2: InternalMatch = { id: 4, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, q2.teamA, q2.teamB), teamB: getLoserTeam(3, s1.teamA, s1.teamB) };
        const gf: InternalMatch = { id: 5, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(3, s1.teamA, s1.teamB), teamB: getWinnerTeam(4, s2.teamA, s2.teamB) };
        return { roundOneMatches: [], quarterMatches: [q0, q1, q2], semiMatches: [s1, s2], grandFinalMatch: gf, allMatches: [q0, q1, q2, s1, s2, gf], hasRoundOne: false };
      }

      const qMatches: InternalMatch[] = [];
      if (numTeams === 8) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }
      const sMatches: InternalMatch[] = [];
      if (numTeams === 8) {
          sMatches.push({ id: 4, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, qMatches[0].teamA, qMatches[0].teamB), teamB: getWinnerTeam(1, qMatches[1].teamA, qMatches[1].teamB) });
          sMatches.push({ id: 5, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, qMatches[2].teamA, qMatches[2].teamB), teamB: getWinnerTeam(3, qMatches[3].teamA, qMatches[3].teamB) });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({ id: i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }
      const gfIndex = numTeams === 8 ? 6 : 2;
      const gf: InternalMatch = { id: gfIndex, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB), teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB) };
      return { roundOneMatches: [], quarterMatches: qMatches, semiMatches: sMatches, grandFinalMatch: gf, allMatches: [...qMatches, ...sMatches, gf], hasRoundOne: false };
  }, [match, scores, globalAssignments, getAssignedPlayer]); 

  const activeMatchData = useMemo(() => {
    const data = allMatches.find(m => m.id === currentMatchIdx);
    if (!data) return undefined;
    if (data.label === 'GRAND FINAL') {
        const sA = scores[`${currentMatchIdx}-A`] || 0;
        const sB = scores[`${currentMatchIdx}-B`] || 0;
        if ((sA + sB) % 2 !== 0) return { ...data, teamA: data.teamB, teamB: data.teamA };
    }
    return data;
  }, [allMatches, currentMatchIdx, scores]);

  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);
    setPhase('TRANSITION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let isSwapped = false;
     if (currentMatchIdx === grandFinalMatch.id) {
         const gamesPlayed = currentScoreA + currentScoreB;
         if (gamesPlayed % 2 !== 0) isSwapped = true;
     }
     let incrementA = 0; let incrementB = 0;
     if (currentRoundWinner === 'azure') { if (isSwapped) incrementB = 1; else incrementA = 1; } 
     else if (currentRoundWinner === 'crimson') { if (isSwapped) incrementA = 1; else incrementB = 1; }
     let newScoreA = currentScoreA + incrementA;
     let newScoreB = currentScoreB + incrementB;
     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));
     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const submitRename = () => {
    if (renameState.player && renameState.newName.trim()) {
        onUpdatePlayer({ ...renameState.player, name: renameState.newName.trim() });
        setRenameState({ isOpen: false, player: null, newName: '' });
    }
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reroll' && wheelState.winnerPlayer && activeMatchData) {
        const side = wheelState.team;
        const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
        const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
        if (teamIdx !== -1) {
            setGlobalAssignments(prev => ({ ...prev, [`${teamIdx}-${wheelState.role}`]: wheelState.winnerPlayer!.id }));
            onReroll(teamIdx, wheelState.role, wheelState.winnerPlayer!);
        }
    }
    setWheelState(null);
  };

  const handleStartGlobalReveal = () => {
     setIsGlobalRolling(true);
     match.teams.forEach((_, idx) => {
         setTimeout(() => {
             setRevealedTeamIndices(prev => new Set(prev).add(idx));
             if (idx === match.teams.length - 1) {
                 setTimeout(() => {
                     setIsGlobalRolling(false);
                     setIsGlobalRevealComplete(true);
                 }, 1500);
             }
         }, (idx + 1) * 2000); // Stagger reveal
     });
  };

  const renderPlayerCard = (role: Role, side: 'azure' | 'crimson') => {
    if (!activeMatchData) return null;
    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
    const player = teamData ? teamData.slots.find(s => s.role === role)?.player : null;
    const isCoach = role === Role.COACH;

    let theme = isCoach ? { bg: 'bg-[#1a1a1a]', border: 'border-white', glow: 'shadow-[0_0_20px_rgba(255,255,255,0.6)]', text: 'text-white', gradient: 'from-white/20 to-transparent' }
      : side === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' }
      : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#c02d2d]/20 to-transparent' };

    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group`}>
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${side === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${side === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {player?.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>

           <div className={`absolute top-2 z-50 flex gap-2 transition-all opacity-0 group-hover:opacity-100 ${side === 'azure' ? 'right-4' : 'left-4'}`}>
              <button onClick={(e) => { 
                  e.stopPropagation(); 
                  if (teamIdx !== -1) {
                      const usedIds = new Set(Object.values(globalAssignments));
                      const candidates = activePlayers.filter(p => !usedIds.has(p.id) && canPlay(p, role));
                      if (candidates.length > 0) {
                          const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
                          setWheelState({ isOpen: true, type: 'reroll', team: side, role, winnerName: newPlayer.name, winnerPlayer: newPlayer, candidates: candidates.map(p => p.name), duration: 4000 });
                      }
                  }
              }} className="p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full text-white hover:text-black transition-all" title="Reroll Player"><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
              <button onClick={(e) => { e.stopPropagation(); if(player) setRenameState({ isOpen: true, player, newName: player.name }); }} className="p-2.5 bg-black/60 hover:bg-[#00d2ff] rounded-full text-white hover:text-black transition-all" title="Change Nickname"><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
           </div>
        </div>
      </div>
    );
  };

  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" style={{ height: `${height}px`, ...style }}>
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b"><animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" /></stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%"><feGaussianBlur stdDeviation="3" result="blur"/><feComposite in="SourceGraphic" in2="blur" operator="over"/></filter>
          </defs>
          {type === 'fork' ? (
             <path d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} stroke="url(#energyLine)" strokeWidth="2.5" fill="none" filter="url(#energyGlow)" strokeLinecap="round" />
          ) : (
             <path d={`M 0,${height/2} L 100,${height/2}`} stroke="url(#energyLine)" strokeWidth="2.5" fill="none" filter="url(#energyGlow)" strokeLinecap="round" />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)"><animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} dur="2s" repeatCount="indefinite" /></circle>
          {type === 'fork' && (<circle r="3" fill="#fff" filter="url(#energyGlow)"><animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" /></circle>)}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: InternalMatch) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;
      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-md p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>
            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>
                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1"><div className="h-[1px] flex-1 bg-white"></div><span className="text-[8px] font-black italic text-[#8a9db8]">VS</span><div className="h-[1px] flex-1 bg-white"></div></div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>
            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-center">
                        <span className="text-[8px] text-[#dcb06b]/50 font-black uppercase tracking-widest">AUTO ADVANCE</span>
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => { const val = e.target.value.replace(/\D/g,'').slice(0,4); setMatchRoomIds(prev => ({ ...prev, [m.id]: val })); }} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----" />
                        </div>
                        {!isDone && m.teamA && m.teamB && <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">START</Button>}
                    </>
                )}
            </div>
        </div>
      );
  };

  const renderTeamRevealScreen = () => {
     return (
        <div className="fixed inset-0 z-[150] bg-[#05090f] overflow-y-auto custom-scrollbar flex flex-col items-center">
            {/* Background FX - Replicating Lobby Feel */}
            <div className="absolute inset-0 bg-[url('https://raw.githubusercontent.com/yoshiharuyamashita/css-fog-animation/master/img/fog1.png')] bg-repeat-x bg-cover opacity-10 animate-fog pointer-events-none"></div>
            <div className="absolute inset-0 bg-[url('https://raw.githubusercontent.com/yoshiharuyamashita/css-fog-animation/master/img/fog2.png')] bg-repeat-x bg-cover opacity-10 animate-fog pointer-events-none" style={{ animationDirection: 'reverse', animationDuration: '30s' }}></div>
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000000_100%)] pointer-events-none"></div>

            <div className="relative z-10 w-full max-w-[1600px] p-4 md:p-8 lg:p-12 flex flex-col items-center min-h-screen">

                {/* Header Section */}
                <div className="text-center mb-12 relative animate-slide-in">
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[120%] h-[120%] bg-[#dcb06b] blur-[120px] opacity-10 pointer-events-none"></div>
                    <h1 className="text-4xl md:text-6xl lg:text-7xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-[#f3dcb1] via-[#dcb06b] to-[#8a6d3b] tracking-[0.15em] drop-shadow-[0_0_30px_rgba(220,176,107,0.4)] mb-4">
                        OFFICIAL DRAFT
                    </h1>
                    <div className="flex items-center justify-center gap-6">
                         <div className="h-[1px] w-12 md:w-24 bg-gradient-to-r from-transparent to-[#dcb06b]"></div>
                         <p className="text-[#8a9db8] font-orbitron tracking-[0.4em] text-[10px] md:text-xs font-bold uppercase">TOURNAMENT ROSTER REVEAL</p>
                         <div className="h-[1px] w-12 md:w-24 bg-gradient-to-l from-transparent to-[#dcb06b]"></div>
                    </div>
                </div>

                {/* Team Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 w-full mb-32">
                    {match.teams.map((team, idx) => {
                        const isRevealed = revealedTeamIndices.has(idx);

                        return (
                            <div 
                                key={idx} 
                                className={`
                                    relative group transition-all duration-700
                                    ${isRevealed ? 'opacity-100 translate-y-0' : 'opacity-70 translate-y-4'}
                                `}
                            >
                                {/* Glow backing for revealed cards */}
                                {isRevealed && <div className="absolute -inset-1 bg-[#dcb06b] blur-lg opacity-20 group-hover:opacity-30 transition-opacity duration-500"></div>}

                                <div className={`
                                    relative bg-[#0a1a2f]/80 backdrop-blur-xl border 
                                    ${isRevealed ? 'border-[#dcb06b] shadow-[0_0_30px_rgba(220,176,107,0.15)]' : 'border-[#1e3a5f]'} 
                                    clip-corner-md p-1 h-full flex flex-col transition-colors duration-500
                                `}>
                                    {/* Scanning Line Animation if rolling */}
                                    {isGlobalRolling && !isRevealed && (
                                        <div className="absolute inset-0 z-20 overflow-hidden clip-corner-md pointer-events-none">
                                            <div className="w-full h-[2px] bg-[#00d2ff] shadow-[0_0_15px_#00d2ff] absolute top-0 animate-[scan_1.5s_linear_infinite]"></div>
                                            <div className="absolute inset-0 bg-gradient-to-b from-[#00d2ff]/10 to-transparent animate-[scan-gradient_1.5s_linear_infinite]"></div>
                                        </div>
                                    )}

                                    {/* Card Header */}
                                    <div className="bg-[#05090f]/80 p-4 border-b border-white/5 relative overflow-hidden group-hover:bg-[#05090f]/90 transition-colors">
                                        <div className="absolute top-0 right-0 p-2 opacity-10">
                                            <span className="text-[50px] font-black font-orbitron text-white leading-none tracking-tighter">{String(idx + 1).padStart(2, '0')}</span>
                                        </div>
                                        <div className="relative z-10 flex flex-col gap-1">
                                            <div className="flex items-center gap-3">
                                                <div className="w-1.5 h-8 shadow-[0_0_10px_currentColor]" style={{ backgroundColor: team.color, color: team.color }}></div>
                                                <h3 className="font-cinzel font-black text-white tracking-widest text-lg truncate drop-shadow-md">{team.name}</h3>
                                            </div>
                                            <div className={`text-[9px] font-orbitron font-bold tracking-wider uppercase pl-5 flex items-center gap-2 ${isRevealed ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>
                                                <div className={`w-1.5 h-1.5 rounded-full ${isRevealed ? 'bg-[#dcb06b] animate-pulse' : 'bg-[#4a5f78]'}`}></div>
                                                {isRevealed ? 'ROSTER CONFIRMED' : 'AWAITING DECRYPTION...'}
                                            </div>
                                        </div>
                                    </div>

                                    {/* Card Body (Roles) */}
                                    <div className="p-4 space-y-3 flex-1 bg-gradient-to-b from-[#0a1a2f]/40 to-[#05090f]/60">
                                        {ROLES_ORDER.map((role, rIdx) => {
                                            const player = getAssignedPlayer(idx, role);
                                            return (
                                                <div key={role} className="flex items-center gap-3 relative group/row">
                                                    {/* Role Icon */}
                                                    <div className={`
                                                        w-8 h-8 flex items-center justify-center rounded bg-[#05090f] border transition-colors duration-300
                                                        ${isRevealed ? 'border-[#dcb06b]/40 text-[#dcb06b] shadow-[0_0_10px_rgba(220,176,107,0.2)]' : 'border-[#1e3a5f] text-[#4a5f78]'}
                                                    `}>
                                                        <div className="scale-75">{RoleIcons[role]}</div>
                                                    </div>

                                                    {/* Player Name */}
                                                    <div className="flex-1 min-w-0 flex flex-col justify-center h-full">
                                                        <span className="text-[7px] text-[#4a5f78] uppercase font-bold tracking-wider leading-none mb-0.5">{role.replace(' Lane', '')}</span>
                                                        <div className={`
                                                            text-sm font-orbitron font-bold truncate transition-colors duration-300
                                                            ${isRevealed ? 'text-white drop-shadow-sm' : 'text-[#1e3a5f]'}
                                                        `}>
                                                            <ScrambleText text={player?.name || '???'} isRevealed={isRevealed} />
                                                        </div>
                                                    </div>

                                                    {/* Tech Decor */}
                                                    {isRevealed && (
                                                        <div className="opacity-0 group-hover/row:opacity-100 transition-opacity">
                                                            <div className="w-1 h-1 bg-[#dcb06b] rounded-full shadow-[0_0_5px_#dcb06b]"></div>
                                                        </div>
                                                    )}
                                                </div>
                                            );
                                        })}
                                    </div>

                                    {/* Card Footer */}
                                    <div className="h-1 w-full flex">
                                        <div className={`h-full flex-1 transition-all duration-1000 ${isRevealed ? 'bg-[#dcb06b] shadow-[0_0_10px_#dcb06b]' : 'bg-[#1e3a5f]'}`}></div>
                                        <div className="h-full w-4 bg-[#05090f]"></div>
                                        <div className={`h-full w-8 transition-all duration-1000 ${isRevealed ? 'bg-[#dcb06b]' : 'bg-[#1e3a5f]'}`}></div>
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>

                {/* Footer Controls */}
                <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-[#05090f] via-[#05090f]/95 to-transparent z-50 flex flex-col items-center pointer-events-none">
                    <div className="pointer-events-auto flex flex-col items-center gap-4">
                        {!isGlobalRevealComplete ? (
                            <button 
                                onClick={handleStartGlobalReveal} 
                                disabled={isGlobalRolling}
                                className={`
                                    group relative px-20 py-5 bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md 
                                    text-[#dcb06b] font-cinzel font-black text-xl tracking-[0.2em] 
                                    hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300
                                    ${isGlobalRolling ? 'opacity-50 cursor-not-allowed' : 'shadow-[0_0_30px_rgba(220,176,107,0.3)] hover:shadow-[0_0_50px_rgba(220,176,107,0.6)] animate-pulse'}
                                `}
                            >
                                <div className="absolute inset-0 bg-[#dcb06b] opacity-0 group-hover:opacity-10 transition-opacity"></div>
                                <span className="relative z-10 flex items-center gap-4">
                                    {isGlobalRolling ? (
                                        <>
                                            <svg className="animate-spin h-6 w-6" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                            DECRYPTING...
                                        </>
                                    ) : (
                                        <>COMMENCE REVEAL</>
                                    )}
                                </span>
                            </button>
                        ) : (
                            <button 
                                onClick={() => setPhase('OVERVIEW')} 
                                className="group relative px-24 py-6 bg-[#dcb06b] text-[#05090f] clip-corner-md font-cinzel font-black text-2xl tracking-[0.2em] hover:bg-white hover:scale-105 transition-all shadow-[0_0_50px_rgba(220,176,107,0.6)]"
                            >
                                ENTER BRACKET
                            </button>
                        )}

                        {!isGlobalRolling && !isGlobalRevealComplete && (
                            <button onClick={() => setPhase('OVERVIEW')} className="text-[#4a5f78] hover:text-[#dcb06b] text-[10px] font-orbitron font-bold uppercase tracking-widest border-b border-transparent hover:border-[#dcb06b] transition-all">
                                Skip Animation &gt;&gt;
                            </button>
                        )}
                    </div>
                </div>
            </div>

            <style>{`
                @keyframes scan {
                    0% { top: 0%; opacity: 0; }
                    10% { opacity: 1; }
                    90% { opacity: 1; }
                    100% { top: 100%; opacity: 0; }
                }
                @keyframes scan-gradient {
                    0% { top: -100%; }
                    100% { top: 100%; }
                }
            `}</style>
        </div>
     );
  };

  if (phase === 'TOURNAMENT_END') return (
      <div className="fixed inset-0 z-[300] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
        <div className="god-rays opacity-40"></div>
        <div className="relative z-20 flex flex-col items-center animate-trophy-pop w-full max-w-4xl">
            <h1 className="text-5xl md:text-8xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] mb-12 tracking-[0.2em] text-center px-4">TOURNAMENT CHAMPIONS</h1>
            <h2 className="text-6xl md:text-9xl font-black font-cinzel text-white text-center drop-shadow-[0_0_20px_#dcb06b] mb-12" style={{ color: tournamentChampion?.color }}>{tournamentChampion?.name}</h2>
            <Button onClick={onReset} size="lg" className="px-24 h-20 text-xl shadow-[0_0_50px_rgba(220,176,107,0.5)]">RETURN TO LOBBY</Button>
        </div>
      </div>
  );

  const overlayBackButton = (
      <div className="fixed top-6 left-6 z-[300]">
            <Button variant="outline" size="sm" onClick={onMinimize} className="bg-black/80 border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black">LOBBY</Button>
      </div>
  );

  if (phase === 'TEAM_REVEAL') return renderTeamRevealScreen();
  if (phase === 'TRANSITION' && activeMatchData) return <>{overlayBackButton}<PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} azureTeamName={activeMatchData.teamA?.name || 'TBD'} crimsonTeamName={activeMatchData.teamB?.name || 'TBD'} onComplete={() => setPhase('DECLARE_WIN')} /></>;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <>{overlayBackButton}<MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now(), azureTeamName: activeMatchData.teamA?.name, crimsonTeamName: activeMatchData.teamB?.name }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} /></>;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} azureTeamName={activeMatchData.teamA?.name} crimsonTeamName={activeMatchData.teamB?.name} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <>{overlayBackButton}<EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now(), azureTeamName: activeMatchData.teamA?.name, crimsonTeamName: activeMatchData.teamB?.name }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} /></>;

  const is16Teams = match.teams.length === 16;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {/* Rename Modal UI */}
      {renameState.isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })}></div>
          <div className="relative w-full max-w-sm bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_30px_rgba(220,176,107,0.3)] animate-slide-in p-6">
            <h3 className="text-[#dcb06b] font-cinzel font-bold text-lg mb-4 text-center tracking-widest">CHANGE NICKNAME</h3>
            <input type="text" value={renameState.newName} onChange={e => setRenameState({ ...renameState, newName: e.target.value })} className="w-full bg-black/50 border border-[#1e3a5f] p-3 text-white font-orbitron focus:border-[#dcb06b] outline-none mb-6 text-center" autoFocus />
            <div className="flex gap-3">
              <Button variant="secondary" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })} className="flex-1">CANCEL</Button>
              <Button onClick={submitRename} className="flex-1">CONFIRM</Button>
            </div>
          </div>
        </div>
      )}

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="absolute top-8 left-8"><Button variant="outline" size="sm" onClick={onMinimize}>LOBBY</Button></div>
          <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-16 uppercase">TOURNAMENT BRACKET</h1>
          <div className={`flex items-center justify-center relative py-20 ${is16Teams ? 'gap-20 md:gap-28' : 'gap-16 md:gap-24'}`}>
            {hasRoundOne && (
                <div className={`flex flex-col relative ${is16Teams ? 'gap-8' : 'gap-8'}`}>
                    {roundOneMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {i % 2 === 0 && <EnergyConnector type="fork" height={218} style={{top:'50%'}}/>}
                        </div>
                    ))}
                </div>
            )}
            <div className={`flex flex-col relative ${is16Teams ? 'gap-[274px]' : 'gap-32'}`}>
                {quarterMatches.map((m, i) => (
                    <div key={m.id} className="relative">
                        {renderBracketMatchCard(m)}
                        {i % 2 === 0 && <EnergyConnector type="fork" height={is16Teams ? 458 : 338} style={{top:'50%'}}/>}
                    </div>
                ))}
            </div>
            <div className={`flex flex-col relative ${is16Teams ? 'gap-[758px]' : 'gap-64'}`}>
                {semiMatches.map((m, i) => (
                    <div key={m.id} className="relative">
                        {renderBracketMatchCard(m)}
                        {i === 0 && <EnergyConnector type="fork" height={is16Teams ? 938 : 458} style={{top:'50%'}}/>}
                    </div>
                ))}
            </div>
            <div className="relative scale-125 ml-10">{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={() => setShowAbortConfirm(true)} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState?.isOpen && <SpinWheel {...wheelState} roleName={wheelState.role} roomId={activeRoomId} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')}>BACK TO BRACKET</Button>
                <div className="text-white font-orbitron font-black text-2xl tracking-[0.4em]">{activeRoomId}</div>
            </div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-32 items-end mb-6">
                    <div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-cyan-400">{activeMatchData?.teamA?.name}</h2></div>
                    <div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-red-500">{activeMatchData?.teamB?.name}</h2></div>
                </div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-32"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-10 left-0 right-0 flex justify-center">
                 <Button onClick={() => setPhase('TRANSITION')} size="lg">INITIALIZE BATTLE</Button>
            </div>
        </div>
      )}
      <ConfirmModal isOpen={showAbortConfirm} title="ABORT TOURNAMENT" message="End tournament?" onConfirm={onReset} onCancel={() => setShowAbortConfirm(false)} isDestructive />
    </div>
  );
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry, BracketMatchResult } from './types';
import { PlayerForm } from './components/PlayerForm';
import { PlayerList } from './components/PlayerList';
import { MatchDisplay } from './components/MatchDisplay';
import { EditPlayerModal } from './components/EditPlayerModal';
import { HistoryList } from './components/HistoryList';
import { generateMatch, generateBracketMatch, validateBracketPool } from './utils/matchmaker';
import { Button } from './components/Button';
import { BackgroundParticles } from './components/BackgroundParticles';
import { LocalClock } from './components/LocalClock';
import { ConfirmModal } from './components/ConfirmModal';
import { BracketDisplay } from './components/BracketDisplay';
import { PreparingModal } from './components/PreparingModal';
import { CookieConsent } from './components/CookieConsent';
import { setCookie, getCookie, eraseCookie } from './utils/cookies';

type ViewMode = 'lobby' | 'match' | 'battle' | 'bracket';
interface Toast { id: string; message: string; isExiting: boolean; }

// Persistence Keys
const STORAGE_KEY_PLAYERS = 'hok_roster_data_v2';
const STORAGE_KEY_HISTORY = 'hok_match_history_v2';
const STORAGE_KEY_ACTIVE_MATCH = 'hok_active_match_session';
const STORAGE_KEY_ACTIVE_BRACKET = 'hok_active_bracket_session';
const COOKIE_CONSENT_KEY = 'hok_cookie_consent_accepted';

const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

export default function App() {
  const [viewMode, setViewMode] = useState<ViewMode>('lobby');
  const [showCookieConsent, setShowCookieConsent] = useState(false);
  const [toasts, setToasts] = useState<Toast[]>([]);

  // --- STATE INITIALIZATION WITH COOKIES (NOW LOCAL STORAGE) ---

  const [players, setPlayers] = useState<Player[]>(() => {
    try {
      if (window.location.hash && window.location.hash.length > 1) {
        const hashData = window.location.hash.substring(1);
        const decoded = JSON.parse(atob(hashData));
        if (Array.isArray(decoded)) return decoded;
      }
      const saved = getCookie(STORAGE_KEY_PLAYERS);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>(() => {
    try {
      const saved = getCookie(STORAGE_KEY_HISTORY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // Load Active Sessions
  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(() => {
      try {
          const saved = getCookie(STORAGE_KEY_ACTIVE_MATCH);
          return saved ? JSON.parse(saved) : null;
      } catch (e) { return null; }
  });

  const [bracketMatch, setBracketMatch] = useState<BracketMatchResult | null>(() => {
      try {
          const saved = getCookie(STORAGE_KEY_ACTIVE_BRACKET);
          return saved ? JSON.parse(saved) : null;
      } catch (e) { return null; }
  });

  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isBracketMode, setIsBracketMode] = useState(false);
  const [numBracketTeams, setNumBracketTeams] = useState(4);
  const [isSetupOpen, setIsSetupOpen] = useState(false);
  const [setupStep, setSetupStep] = useState<1 | 2 | 3>(1); // 1: Config, 2: Roster, 3: Launch
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  const [isPreparing, setIsPreparing] = useState(false);
  const [prepMessage, setPrepMessage] = useState("");
  const [prepError, setPrepError] = useState<string | null>(null);

  const [confirmState, setConfirmState] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    onConfirm: () => void;
    isDestructive?: boolean;
  }>({
    isOpen: false,
    title: '',
    message: '',
    onConfirm: () => {},
  });

  // --- FULLSCREEN LOGIC ---
  const enableFullscreen = useCallback(() => {
    const elem = document.documentElement;
    if (!document.fullscreenElement) {
        const req = elem.requestFullscreen || (elem as any).webkitRequestFullscreen || (elem as any).msRequestFullscreen;
        if (req) {
            req.call(elem).catch((err: any) => console.log("Fullscreen request blocked or failed:", err));
        }
    }
  }, []);

  const toggleFullscreen = useCallback(() => {
    if (!document.fullscreenElement) {
        enableFullscreen();
    } else {
        if (document.exitFullscreen) {
            document.exitFullscreen();
        }
    }
  }, [enableFullscreen]);

  useEffect(() => {
      const activate = () => {
          enableFullscreen();
          window.removeEventListener('click', activate);
          window.removeEventListener('touchstart', activate);
          window.removeEventListener('keydown', activate);
      };
      window.addEventListener('click', activate);
      window.addEventListener('touchstart', activate);
      window.addEventListener('keydown', activate);
      return () => {
          window.removeEventListener('click', activate);
          window.removeEventListener('touchstart', activate);
          window.removeEventListener('keydown', activate);
      };
  }, [enableFullscreen]);

  useEffect(() => {
    const hasConsented = getCookie(COOKIE_CONSENT_KEY);
    if (!hasConsented) setShowCookieConsent(true);
  }, []);

  const handleAcceptCookies = () => {
    setCookie(COOKIE_CONSENT_KEY, 'true', 365);
    setShowCookieConsent(false);
    enableFullscreen();
  };

  useEffect(() => {
    setCookie(STORAGE_KEY_PLAYERS, JSON.stringify(players), 30);
    try {
      const compactData = players.map(p => ({
        id: p.id,
        name: p.name,
        roles: p.roles,
        isAllRoles: p.isAllRoles,
        isActive: p.isActive,
        stats: p.stats
      }));
      const hash = btoa(JSON.stringify(compactData));
      if (hash.length < 50000) {
         window.history.replaceState(null, '', `#${hash}`);
      }
    } catch (e) {}
  }, [players]);

  useEffect(() => {
    setCookie(STORAGE_KEY_HISTORY, JSON.stringify(matchHistory), 30);
  }, [matchHistory]);

  useEffect(() => {
      if (currentMatch) {
          setCookie(STORAGE_KEY_ACTIVE_MATCH, JSON.stringify(currentMatch), 1);
      } else {
          eraseCookie(STORAGE_KEY_ACTIVE_MATCH);
      }
  }, [currentMatch]);

  useEffect(() => {
      if (bracketMatch) {
          setCookie(STORAGE_KEY_ACTIVE_BRACKET, JSON.stringify(bracketMatch), 1);
      } else {
          eraseCookie(STORAGE_KEY_ACTIVE_BRACKET);
      }
  }, [bracketMatch]);

  const navigate = useCallback((mode: ViewMode, data: any) => {
    setViewMode(mode);
    if (mode === 'lobby' && Array.isArray(data)) setPlayers(data);
    else if ((mode === 'match' || mode === 'battle') && data) setCurrentMatch(data);
    else if (mode === 'bracket' && data) setBracketMatch(data);
  }, []);

  const handleBackToLobby = () => {
      setViewMode('lobby');
  };

  const handleResumeSession = () => {
      if (currentMatch) {
          setViewMode('match');
      } else if (bracketMatch) {
          setViewMode('bracket');
      }
  };

  const hasActiveSession = !!currentMatch || !!bracketMatch;

  const dismissToast = (id: string) => {
      setToasts(prev => prev.map(t => t.id === id ? { ...t, isExiting: true } : t));
      setTimeout(() => {
          setToasts(prev => prev.filter(t => t.id !== id));
      }, 1000);
  };

  const addToast = (message: string) => {
      const id = Date.now().toString() + Math.random().toString();
      setToasts(prev => [...prev, { id, message, isExiting: false }]);
      setTimeout(() => {
          dismissToast(id);
      }, 1500);
  };

  const handleBatchProcess = (batchData: { name: string; roles: Role[]; isAllRoles: boolean; action?: 'add' | 'bench' }[]) => {
    setPlayers(prev => {
      let updatedPlayers = [...prev];
      batchData.forEach(item => {
        const normalizedName = item.name.trim().toLowerCase();
        const existingIndex = updatedPlayers.findIndex(p => p.name.trim().toLowerCase() === normalizedName);
        if (item.action === 'bench') {
           if (existingIndex !== -1) updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], isActive: false };
        } else {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], roles: item.roles, isAllRoles: item.isAllRoles, isActive: true };
           } else {
              updatedPlayers.push({
                 id: crypto.randomUUID(),
                 name: item.name,
                 roles: item.roles,
                 isAllRoles: item.isAllRoles,
                 isActive: true,
                 isLastMatchMvp: false,
                 stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
              });
           }
        }
      });
      return updatedPlayers;
    });
    setErrorMsg(null);
    batchData.forEach((item, index) => {
        setTimeout(() => {
            if (item.action === 'bench') {
                 addToast(`${item.name} :: BENCHED`);
            } else {
                 const roleDisplay = item.isAllRoles ? 'ALL ROLES' : item.roles.map(r => r.replace(' Lane', '')).join(', ').toUpperCase();
                 addToast(`${item.name} :: ${roleDisplay}`);
            }
        }, index * 300);
    });
  };

  const removePlayer = (id: string) => setPlayers(prev => prev.filter(p => p.id !== id));
  const togglePlayerActive = (id: string) => setPlayers(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p));
  const handleEditPlayer = (player: Player) => { setEditingPlayer(player); setIsEditModalOpen(true); };

  const handleUpdatePlayer = (updatedPlayer: Player) => {
    setPlayers(prev => prev.map(p => p.id === updatedPlayer.id ? updatedPlayer : p));
    if (currentMatch) {
       setCurrentMatch(prev => {
          if (!prev) return null;
          return {
             ...prev,
             azureTeam: prev.azureTeam.map(slot => slot.player.id === updatedPlayer.id ? { ...slot, player: { ...slot.player, name: updatedPlayer.name } } : slot),
             crimsonTeam: prev.crimsonTeam.map(slot => slot.player.id === updatedPlayer.id ? { ...slot, player: { ...slot.player, name: updatedPlayer.name } } : slot)
          };
       });
    }
    if (bracketMatch) {
       setBracketMatch(prev => {
          if (!prev) return null;
          return {
             ...prev,
             teams: prev.teams.map(team => ({
                 ...team,
                 slots: team.slots.map(slot => slot.player.id === updatedPlayer.id ? { ...slot, player: { ...slot.player, name: updatedPlayer.name } } : slot)
             }))
          };
       });
    }
  };

  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = async () => {
    if (!isBracketMode) {
      if (!roomId.trim() || roomId.length < 4) { setErrorMsg("Please enter a valid 4-digit Room ID."); return; }
    }

    setCurrentMatch(null);
    setBracketMatch(null);
    setErrorMsg(null);
    setIsPreparing(true);
    setPrepError(null);
    setPrepMessage("CONNECTING TO SERVER...");

    try {
        await delay(1000);
        setPrepMessage("SCANNING ACTIVE ROSTER...");
        await delay(1200);
        setPrepMessage("VALIDATING ROLE COMPATIBILITY...");
        await delay(800);

        if (isBracketMode) {
            const validation = validateBracketPool(activePlayers, numBracketTeams);
            if (!validation.valid) throw new Error(validation.error);
            const result = generateBracketMatch(activePlayers, roomId, numBracketTeams);
            if (result) { 
                setPrepMessage("GENERATING TOURNAMENT BRACKET...");
                await delay(800);
                setBracketMatch(result); 
                setViewMode('bracket'); 
                setIsSetupOpen(false);
            } else { throw new Error("FAILED TO GENERATE BRACKET STRUCTURE."); }
        } else {
            const required = isCoachMode ? 12 : 10;
            if (activePlayers.length < required) throw new Error(`INSUFFICIENT PLAYERS: Need ${required} active players.`);
            const result = generateMatch(activePlayers, roomId, isCoachMode);
            if (result) { 
                setPrepMessage("FINALIZING BATTLE DATA...");
                await delay(800);
                setCurrentMatch(result); 
                navigate('match', result); 
                setIsSetupOpen(false);
            } else { throw new Error("IMPOSSIBLE COMPOSITION."); }
        }
        setIsPreparing(false);
    } catch (err: any) {
        setPrepError(err.message || "Unknown Error Occurred");
    }
  };

  const handleExportRoster = () => {
    if (players.length === 0) { alert("Roster is empty."); return; }
    const lines = players.map(p => {
        const name = p.name.trim();
        const roles = p.isAllRoles ? 'All Role' : p.roles.map(r => r === Role.JUNGLE ? 'Jungle' : r).join(', ');
        return `${name} : ${roles}`;
    });
    navigator.clipboard.writeText(lines.join('\n')).then(() => alert("Roster saved to clipboard!"));
  };

  const handleClearAll = () => {
    setConfirmState({
      isOpen: true,
      title: "CLEAR ROSTER",
      message: "This will permanently delete ALL players from your squad list.",
      isDestructive: true,
      onConfirm: () => setPlayers([]),
    });
  };

  const handleRerollSlot = (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => {
    if (!currentMatch) return;
    const updatedMatch = {
        ...currentMatch,
        azureTeam: currentMatch.azureTeam.map(slot => (team === 'azure' && slot.role === role) ? { ...slot, player: newPlayer } : slot),
        crimsonTeam: currentMatch.crimsonTeam.map(slot => (team === 'crimson' && slot.role === role) ? { ...slot, player: newPlayer } : slot)
    };
    setCurrentMatch(updatedMatch); navigate('match', updatedMatch);
  };

  const handleBracketReroll = (teamIndex: number, role: Role, newPlayer: Player) => {
    if (!bracketMatch) return;
    const updatedTeams = bracketMatch.teams.map((team, idx) => {
        if (idx === teamIndex) {
            return { ...team, slots: team.slots.map(slot => slot.role === role ? { ...slot, player: newPlayer } : slot) };
        }
        return team;
    });
    setBracketMatch({ ...bracketMatch, teams: updatedTeams });
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => {
    if (!currentMatch) return;
    const historyEntry = { ...currentMatch, id: crypto.randomUUID(), winningTeam: winner, mvpId, ratings };
    setMatchHistory(prev => [historyEntry, ...prev]);

    const azureIds = new Set(currentMatch.azureTeam.map(slot => slot.player.id));
    const crimsonIds = new Set(currentMatch.crimsonTeam.map(slot => slot.player.id));
    const allMatchIds = new Set([...azureIds, ...crimsonIds]);

    const updatedPlayers = players.map(p => {
      let isLastMatchMvp = mvpId === p.id;
      if (!allMatchIds.has(p.id)) return { ...p, isLastMatchMvp: false };
      const isAzure = azureIds.has(p.id);
      const isWinner = winner && ((isAzure && winner === 'azure') || (!isAzure && winner === 'crimson'));
      const newStats = { ...p.stats, matchesPlayed: p.stats.matchesPlayed + 1 };
      if (winner) {
        if (isWinner) {
           newStats.wins += 1; newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) newStats.maxStreak = newStats.currentStreak;
        } else { newStats.currentStreak = 0; }
      }
      return { ...p, stats: newStats, isLastMatchMvp, lastMatchRating: ratings?.[p.id] || 0 };
    });

    setPlayers(updatedPlayers); 
    setCurrentMatch(null); 
    eraseCookie(STORAGE_KEY_ACTIVE_MATCH);
    navigate('lobby', updatedPlayers);
    setRoomId('');
  };

  const handleClearHistory = () => {
    setConfirmState({
      isOpen: true,
      title: "ERASE HISTORY",
      message: "This will permanently delete all recorded battle logs.",
      isDestructive: true,
      onConfirm: () => setMatchHistory([]),
    });
  };

  const isRoomReady = roomId.length === 4;

  const renderSetupWizard = () => {
    return (
        <div className="flex flex-col min-h-0 overflow-hidden h-full">
             <div className="shrink-0 mb-6">
                 <div className="flex items-center justify-between px-8 mb-2">
                     <button onClick={() => setSetupStep(1)} className={`text-[10px] font-orbitron font-bold tracking-[0.2em] transition-colors hover:text-white cursor-pointer ${setupStep >= 1 ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>01 CONFIG</button>
                     <button onClick={() => setSetupStep(2)} className={`text-[10px] font-orbitron font-bold tracking-[0.2em] transition-colors hover:text-white cursor-pointer ${setupStep >= 2 ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>02 ROSTER</button>
                     <button onClick={() => setSetupStep(3)} className={`text-[10px] font-orbitron font-bold tracking-[0.2em] transition-colors hover:text-white cursor-pointer ${setupStep >= 3 ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>03 LAUNCH</button>
                 </div>
                 <div className="h-1 w-full bg-[#0a1a2f] flex">
                     <div className={`flex-1 transition-all duration-500 ${setupStep >= 1 ? 'bg-[#dcb06b] shadow-[0_0_10px_#dcb06b]' : 'bg-[#1e3a5f]'}`}></div>
                     <div className={`flex-1 transition-all duration-500 border-l border-[#0a1a2f] ${setupStep >= 2 ? 'bg-[#dcb06b] shadow-[0_0_10px_#dcb06b]' : 'bg-[#1e3a5f]'}`}></div>
                     <div className={`flex-1 transition-all duration-500 border-l border-[#0a1a2f] ${setupStep >= 3 ? 'bg-[#dcb06b] shadow-[0_0_10px_#dcb06b]' : 'bg-[#1e3a5f]'}`}></div>
                 </div>
             </div>

             <div className="flex-1 overflow-y-auto overflow-x-hidden custom-scrollbar p-1 px-4 md:px-8">
                {setupStep === 1 && (
                    <div className="animate-slide-in space-y-6 md:space-y-8">
                         {isBracketMode ? (
                          <div className="relative group opacity-80">
                            <div className="absolute -inset-[1px] bg-gradient-to-b from-white/10 to-transparent clip-corner-sm opacity-20"></div>
                            <div className="bg-[#0a1a2f]/60 backdrop-blur-sm p-4 clip-corner-sm border border-[#1e3a5f] relative">
                              <div className="flex justify-between items-center">
                                  <div className="flex items-center gap-2">
                                    <div className="w-1.5 h-1.5 bg-gray-500 rounded-full"></div>
                                    <h3 className="text-xs text-[#8a9db8] font-cinzel font-bold tracking-[0.2em] uppercase">Battle Room</h3>
                                  </div>
                                  <span className="text-[9px] px-2 py-0.5 border border-white/10 rounded text-white/40 font-bold">AUTO-ASSIGN</span>
                              </div>
                              <div className="mt-2 text-[10px] text-[#4a5f78] font-orbitron tracking-wide leading-tight">Room IDs will be assigned individually per match.</div>
                            </div>
                          </div>
                        ) : (
                          <div className="relative group">
                            <div className="absolute -inset-[1px] bg-gradient-to-b from-[#dcb06b]/50 to-transparent clip-corner-md opacity-30"></div>
                            <div className="bg-[#0a1a2f]/90 backdrop-blur-md p-6 clip-corner-md relative overflow-hidden">
                              <div className="flex items-center justify-between mb-4 border-b border-[#dcb06b]/20 pb-2">
                                <h3 className="text-sm text-[#dcb06b] font-cinzel font-bold tracking-[0.2em] uppercase">Battle Room</h3>
                                <span className={`text-[10px] font-orbitron font-bold transition-colors duration-300 ${isRoomReady ? 'text-green-500' : 'text-red-500'}`}>LOBBY STATUS: {isRoomReady ? 'READY' : 'NOT READY'}</span>
                              </div>
                              <div className="relative"><input type="text" value={roomId} onChange={(e) => setRoomId(e.target.value.replace(/\D/g,'').slice(0,4))} placeholder="0000" className={`relative z-10 bg-black/40 border border-[#1e3a5f] p-4 text-3xl md:text-5xl font-orbitron font-black w-full text-center focus:outline-none tracking-[0.4em] transition-all duration-300 clip-corner-sm ${roomId ? 'text-white border-[#dcb06b] shadow-[0_0_15px_rgba(220,176,107,0.2)] animate-[chromatic_0.2s_infinite]' : 'text-[#4a5f78] opacity-60'} placeholder-[#1e3a5f]`} /></div>
                            </div>
                          </div>
                        )}

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                          {!isBracketMode && (
                            <button onClick={() => setIsCoachMode(!isCoachMode)} className="relative w-full group overflow-hidden p-[3px] clip-corner-sm transition-all duration-300 transform hover:scale-[1.01] active:scale-[0.98]">
                              {isCoachMode && <div className="absolute inset-[-100%] transition-opacity duration-700"><div className="absolute inset-0 bg-[conic-gradient(from_0deg,transparent_0deg,#dcb06b_60deg,#f3dcb1_120deg,transparent_180deg,#dcb06b_240deg,#f3dcb1_300deg,transparent_360deg)] animate-[spin_3s_linear_infinite]"></div></div>}
                              <div className={`relative z-10 py-4 px-6 flex items-center justify-center transition-all duration-300 clip-corner-sm border h-full ${isCoachMode ? 'bg-black text-[#dcb06b] border-transparent shadow-[inset_0_0_20px_rgba(220,176,107,0.5)]' : 'bg-[#0a1a2f]/80 border-[#1e3a5f] text-[#4a5f78]'}`}><span className={`font-cinzel font-black text-xs tracking-[0.3em] uppercase transition-all duration-500 ${isCoachMode ? 'text-white drop-shadow-[0_0_10px_#dcb06b]' : ''}`}>COACH MODE {isCoachMode ? 'ON' : 'OFF'}</span></div>
                            </button>
                          )}
                          <button onClick={() => { setIsBracketMode(!isBracketMode); if(!isBracketMode) setIsCoachMode(false); }} className="relative w-full group overflow-hidden p-[3px] clip-corner-sm transition-all duration-300 transform hover:scale-[1.01] active:scale-[0.98]">
                            {isBracketMode && <div className="absolute inset-[-100%] transition-opacity duration-700"><div className="absolute inset-0 bg-[conic-gradient(from_0deg,transparent_0deg,#ffffff_60deg,#e2e8f0_120deg,transparent_180deg,#ffffff_240deg,#e2e8f0_300deg,transparent_360deg)] animate-[spin_3s_linear_infinite]"></div></div>}
                            <div className={`relative z-10 py-4 px-6 flex items-center justify-center transition-all duration-300 clip-corner-sm border h-full ${isBracketMode ? 'bg-black text-white border-transparent shadow-[inset_0_0_20px_rgba(255,255,255,0.4)]' : 'bg-[#0a1a2f]/80 border-[#1e3a5f] text-[#4a5f78]'}`}><span className={`font-cinzel font-black text-xs tracking-[0.3em] uppercase transition-all duration-500 ${isBracketMode ? 'text-white drop-shadow-[0_0_10px_rgba(255,255,255,0.8)]' : ''}`}>BRACKET MODE {isBracketMode ? 'ON' : 'OFF'}</span></div>
                          </button>
                        </div>

                        {isBracketMode && (
                          <div className="relative animate-slide-in">
                            <div className="bg-[#0a1a2f]/80 border border-[#dcb06b]/30 p-4 clip-corner-sm">
                                <div className="text-[10px] text-[#8a9db8] font-black uppercase tracking-widest mb-3 flex justify-between"><span>Number of Teams</span><span className="text-white font-orbitron">{numBracketTeams} TEAMS</span></div>
                                <div className="flex gap-1">{[3, 4, 5, 6, 8, 12, 16].map(n => (<button key={n} onClick={() => setNumBracketTeams(n)} className={`flex-1 py-2 font-orbitron font-bold text-xs clip-corner-sm border transition-all ${numBracketTeams === n ? 'bg-[#dcb06b] text-black border-[#dcb06b] shadow-[0_0_10px_#dcb06b]' : 'bg-black/40 text-[#4a5f78] border-[#1e3a5f]'}`}>{n}</button>))}</div>
                                <div className="mt-2 text-[8px] text-[#4a5f78] uppercase text-center font-bold tracking-widest">Requires {numBracketTeams * 5} active players</div>
                            </div>
                          </div>
                        )}
                    </div>
                )}

                {setupStep === 2 && (
                    <div className="animate-slide-in">
                        <PlayerForm onBatchProcess={handleBatchProcess} isCoachMode={isCoachMode} />
                    </div>
                )}

                {setupStep === 3 && (
                    <div className="animate-slide-in space-y-6">
                        <div className="relative group">
                          <div className="absolute -inset-[1px] bg-gradient-to-b from-[#dcb06b]/50 to-transparent clip-corner-md opacity-30"></div>
                          <div className="bg-[#0a1a2f]/90 backdrop-blur-md p-6 clip-corner-md relative">
                            <div className="flex justify-between items-end mb-6">
                                <div><div className="text-[#8a9db8] text-[10px] uppercase font-bold mb-1">Active Players</div><div className="flex items-baseline gap-2"><div className="text-5xl font-orbitron font-bold text-white">{activePlayers.length}</div><div className="text-xl font-orbitron font-bold text-[#4a5f78]">/ {players.length}</div></div></div>
                            </div>

                            <div className="mb-6 p-4 bg-black/40 border border-[#1e3a5f] clip-corner-sm">
                                <h4 className="text-[#dcb06b] font-cinzel text-xs font-bold mb-2 tracking-widest">REQUIREMENTS</h4>
                                <div className="space-y-2">
                                    <div className="flex justify-between text-[10px] uppercase">
                                        <span className="text-[#8a9db8]">Minimum Players</span>
                                        <span className={activePlayers.length >= (isBracketMode ? numBracketTeams * 5 : (isCoachMode ? 12 : 10)) ? "text-green-500" : "text-red-500"}>
                                            {isBracketMode ? numBracketTeams * 5 : (isCoachMode ? 12 : 10)} REQ
                                        </span>
                                    </div>
                                    {!isBracketMode && (
                                        <div className="flex justify-between text-[10px] uppercase">
                                            <span className="text-[#8a9db8]">Room ID</span>
                                            <span className={isRoomReady ? "text-green-500" : "text-red-500"}>{isRoomReady ? "VALID" : "INVALID"}</span>
                                        </div>
                                    )}
                                </div>
                            </div>
                            {errorMsg && <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/20 text-red-200 text-xs animate-pulse">{errorMsg}</div>}
                          </div>
                        </div>
                    </div>
                )}
             </div>

             <div className="shrink-0 p-4 md:p-8 pt-4 border-t border-[#1e3a5f] bg-[#05090f]/50 flex justify-between gap-4">
                 {setupStep > 1 ? (
                     <Button variant="secondary" onClick={() => setSetupStep(prev => (prev - 1) as 1|2|3)} className="w-32 border-[#1e3a5f] text-[#4a5f78] hover:text-white">BACK</Button>
                 ) : (
                     <div className="w-32"></div>
                 )}

                 {setupStep < 3 ? (
                     <Button onClick={() => setSetupStep(prev => (prev + 1) as 1|2|3)} className="flex-1 max-w-xs">NEXT STEP</Button>
                 ) : (
                     <Button onClick={handleGenerate} disabled={activePlayers.length < (isBracketMode ? numBracketTeams * 5 : (isCoachMode ? 12 : 10)) || (!isBracketMode && !isRoomReady)} className="flex-1 max-w-xs shadow-[0_0_20px_rgba(220,176,107,0.3)] animate-pulse">START MATCHMAKING</Button>
                 )}
             </div>
        </div>
    );
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative flex flex-col">
      <BackgroundParticles />
      <LocalClock />

      <div className="fixed top-24 right-4 z-[3000] flex flex-col gap-2 pointer-events-none">
          {toasts.map(toast => (
              <div 
                key={toast.id} 
                className={`bg-[#0a1a2f]/95 border border-[#dcb06b] p-4 clip-corner-sm shadow-[0_0_20px_rgba(220,176,107,0.3)] pointer-events-auto flex items-center gap-3 min-w-[300px] transition-opacity duration-1000 ease-in-out ${toast.isExiting ? 'opacity-0' : 'opacity-100 animate-slide-in'}`}
              >
                  <div className="w-2 h-2 bg-[#dcb06b] rounded-full animate-pulse"></div>
                  <span className="text-[#dcb06b] font-orbitron text-xs font-bold tracking-wide uppercase flex-1">{toast.message}</span>
                  <button onClick={() => dismissToast(toast.id)} className="text-[#4a5f78] hover:text-white transition-colors ml-2">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                      </svg>
                  </button>
              </div>
          ))}
      </div>

      <PreparingModal isOpen={isPreparing} message={prepMessage} error={prepError} onClose={() => setIsPreparing(false)} />
      <ConfirmModal 
        isOpen={confirmState.isOpen}
        title={confirmState.title}
        message={confirmState.message}
        onConfirm={confirmState.onConfirm}
        onCancel={() => setConfirmState(prev => ({ ...prev, isOpen: false }))}
        isDestructive={confirmState.isDestructive}
      />
      {showCookieConsent && <CookieConsent onAccept={handleAcceptCookies} />}

      <div className="fixed inset-0 bg-black -z-10">
         <img src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" alt="HoK" className="absolute inset-0 w-full h-full object-cover opacity-50" />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 via-[#05090f]/60 to-[#05090f] mix-blend-multiply"></div>
      </div>

      {editingPlayer && <EditPlayerModal player={editingPlayer} isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} onSave={handleUpdatePlayer} />}

      {viewMode === 'lobby' && (
        <>
          <main className="relative z-10 pt-16 px-4 flex-grow max-w-7xl mx-auto w-full">
            {hasActiveSession && (
                <div className="mb-6 animate-slide-in">
                    <button 
                        onClick={handleResumeSession}
                        className="w-full bg-[#0a1a2f]/90 border border-[#dcb06b] clip-corner-md p-6 flex items-center justify-between group hover:bg-[#dcb06b]/10 transition-colors shadow-[0_0_20px_rgba(220,176,107,0.2)]"
                    >
                         <div className="flex items-center gap-4">
                             <div className="w-12 h-12 flex items-center justify-center bg-[#dcb06b]/20 rounded-full border border-[#dcb06b] animate-pulse">
                                 <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-[#dcb06b]" viewBox="0 0 20 20" fill="currentColor">
                                     <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
                                 </svg>
                             </div>
                             <div className="text-left">
                                 <h3 className="text-[#dcb06b] font-cinzel font-bold text-xl tracking-widest">SESSION IN PROGRESS</h3>
                                 <p className="text-[#8a9db8] font-orbitron text-xs tracking-wide">
                                     {currentMatch ? 'RANKED DRAFT • BATTLEFIELD' : 'TOURNAMENT BRACKET • MANAGEMENT'}
                                 </p>
                             </div>
                         </div>
                         <div className="text-[#dcb06b] font-bold font-orbitron tracking-[0.2em] group-hover:translate-x-2 transition-transform">
                             RESUME &gt;&gt;
                         </div>
                    </button>
                </div>
            )}

            {isSetupOpen && (
              <div className="fixed inset-0 z-[100] bg-[#05090f]/95 backdrop-blur-xl flex items-center justify-center p-2 md:p-4 animate-slide-in">
                 <div className="w-full max-w-2xl bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md relative shadow-[0_0_100px_rgba(0,0,0,0.8)] max-h-[90vh] h-auto flex flex-col">
                    <div className="flex items-center justify-between p-4 md:p-6 border-b border-[#1e3a5f] bg-[#05090f]/50 shrink-0">
                       <h2 className="text-[#dcb06b] font-cinzel font-black text-lg md:text-xl tracking-[0.2em] flex items-center gap-3">
                          <div className="w-2 h-6 md:h-8 bg-[#dcb06b]"></div>
                          BATTLE CONFIGURATION
                       </h2>
                       <button onClick={() => setIsSetupOpen(false)} className="text-[#4a5f78] hover:text-white transition-colors">
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 md:h-8 md:w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" />
                          </svg>
                       </button>
                    </div>
                    {renderSetupWizard()}
                 </div>
              </div>
            )}
            <div className="w-full">
                 <div className="flex flex-col md:flex-row items-center justify-between mb-6 gap-4">
                    <button onClick={() => setIsSetupOpen(true)} className="group relative px-8 py-3 bg-[#0a1a2f] border border-[#dcb06b] clip-corner-sm text-[#dcb06b] font-cinzel font-bold tracking-[0.2em] hover:bg-[#dcb06b] hover:text-[#05090f] transition-all shadow-[0_0_15px_rgba(220,176,107,0.2)]">
                       <span className="flex items-center gap-2"><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>OPEN COMMAND CENTER</span>
                    </button>
                    <h2 className="text-3xl font-cinzel font-black text-[#dcb06b] tracking-widest hidden md:block">SQUAD ROSTER</h2>
                    <div className="flex gap-3">
                      <button onClick={toggleFullscreen} className="px-6 py-3 border border-[#dcb06b]/30 text-[#dcb06b]/80 hover:text-[#dcb06b] hover:border-[#dcb06b] hover:bg-[#dcb06b]/5 transition-all text-[10px] uppercase font-bold tracking-[0.2em] clip-corner-sm flex items-center justify-center gap-2 group"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 group-hover:scale-110 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" /></svg>Screen</button>
                      <button onClick={handleExportRoster} className="px-6 py-3 border border-[#dcb06b]/30 text-[#dcb06b]/80 hover:text-[#dcb06b] hover:border-[#dcb06b] hover:bg-[#dcb06b]/5 transition-all text-[10px] uppercase font-bold tracking-[0.2em] clip-corner-sm flex items-center justify-center gap-2 group"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 group-hover:scale-110 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4" /></svg>Save</button>
                      <button onClick={handleClearAll} className="px-6 py-3 border border-red-500/30 text-red-500/80 hover:text-red-500 hover:border-red-500 hover:bg-red-500/5 transition-all text-[10px] uppercase font-bold tracking-[0.2em] clip-corner-sm flex items-center justify-center gap-2 group"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 group-hover:scale-110 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>Clear</button>
                    </div>
                 </div>
                 <div className="tech-border p-6 bg-[#0a1a2f]/40 min-h-[400px]">
                    <PlayerList players={players} onRemove={removePlayer} onToggleActive={togglePlayerActive} onEdit={handleEditPlayer} isSidebarOpen={false} />
                 </div>
                 <div className="mt-12 tech-border p-6 bg-[#0a1a2f]/40">
                    <h2 className="text-2xl font-cinzel font-black text-[#dcb06b] mb-6">BATTLE HISTORY</h2>
                    <HistoryList history={matchHistory} onClear={handleClearHistory} />
                 </div>
            </div>
          </main>
          <footer className="py-12 px-6 text-center border-t border-[#dcb06b]/10 bg-[#05090f] mt-auto">
              <div className="max-w-4xl mx-auto flex flex-col items-center gap-4">
                  <div className="w-12 h-0.5 bg-gradient-to-r from-transparent via-[#dcb06b] to-transparent mb-2"></div>
                  <div className="text-[#dcb06b] font-cinzel font-black text-sm tracking-[0.2em] mb-1">APPLICATION DEVELOPED BY KAZEHUNT</div>
                  <div className="text-[#4a5f78] font-orbitron text-[9px] leading-relaxed tracking-[0.1em] uppercase max-w-2xl flex flex-col gap-2"><p>DESIGNED EXCLUSIVELY FOR HONOR OF KINGS CUSTOM FUN MATCHES ON THE OFFICIAL DISCORD. THE DEVELOPER ASSUMES NO RESPONSIBILITY FOR USAGE OUTSIDE THIS INTENDED SCOPE.</p></div>
              </div>
          </footer>
        </>
      )}

      {currentMatch && viewMode !== 'lobby' && viewMode !== 'bracket' && (
        <MatchDisplay 
          match={currentMatch} 
          activePlayers={activePlayers} 
          initialMode={viewMode === 'battle' ? 'battle' : 'draft'}
          onReset={() => { 
              setCurrentMatch(null); 
              eraseCookie(STORAGE_KEY_ACTIVE_MATCH);
              setViewMode('lobby'); 
          }}
          onMinimize={handleBackToLobby}
          onCompleteMatch={handleMatchFinish}
          onReroll={handleRerollSlot}
          onStartBattle={() => setViewMode('battle')}
          onUpdatePlayer={handleUpdatePlayer}
        />
      )}

      {bracketMatch && viewMode === 'bracket' && (
        <BracketDisplay 
          match={bracketMatch} 
          onReset={() => { 
              setBracketMatch(null); 
              eraseCookie(STORAGE_KEY_ACTIVE_BRACKET);
              setViewMode('lobby'); 
          }} 
          onMinimize={handleBackToLobby}
          activePlayers={activePlayers}
          onReroll={handleBracketReroll}
          onUpdatePlayer={handleUpdatePlayer}
        />
      )}

      <style>{`@keyframes chromatic { 0% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; } 25% { text-shadow: -2px 0 0 #ff0000, 2px 0 0 #0000ff; } 50% { text-shadow: 2px -1px 0 #ff0000, -2px 1px 0 #0000ff; } 75% { text-shadow: -2px 1px 0 #ff0000, 2px -1px 0 #0000ff; } 100% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; } }`}</style>
    </div>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
